// DELETE /api/v4/files/delete?path=relative/path
// Moves a file or directory to trash. Refuses empty path (won't delete user root).
srv.Post("/api/v4/files/delete", [&](const httplib::Request& req, httplib::Response& res) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;

    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto audit_fail = [&](const std::string& reason, int http, const std::string& detail = "") {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_delete_fail";
        ev.outcome = "fail";
        ev.f["fingerprint"] = fp_hex;
        ev.f["reason"] = reason;
        ev.f["http"] = std::to_string(http);
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);

        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    auto audit_ok = [&](const std::string& rel_path, const std::string& type,
                        std::uint64_t freed_bytes) {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_delete_ok";
        ev.outcome = "ok";
        ev.f["fingerprint"] = fp_hex;
        ev.f["path"] = pqnas::shorten(rel_path, 200);
        ev.f["type"] = type;
        ev.f["freed_bytes"] = std::to_string((unsigned long long)freed_bytes);

        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    auto audit_warn = [&](const std::string& reason,
                          const std::string& detail,
                          const std::string& rel_path) {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_delete_warn";
        ev.outcome = "warn";
        ev.f["fingerprint"] = fp_hex;
        ev.f["reason"] = reason;
        ev.f["path"] = pqnas::shorten(rel_path, 200);
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;
        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    auto uopt = users.get(fp_hex);
    if (!uopt.has_value()) {
        audit_fail("user_missing", 403);
        reply_json(res, 403, json{
            {"ok", false},
            {"error", "forbidden"},
            {"message", "policy denied"}
        }.dump());
        return;
    }
    const auto u = *uopt;

    if (u.storage_state != "allocated") {
        audit_fail("storage_unallocated", 403);
        reply_json(res, 403, json{
            {"ok", false},
            {"error", "storage_unallocated"},
            {"message", "Storage not allocated"},
            {"fingerprint_hex", fp_hex},
            {"quota_bytes", u.quota_bytes}
        }.dump());
        return;
    }

    std::string rel_path;
    if (req.has_param("path")) rel_path = req.get_param_value("path");
    if (rel_path.empty()) {
        audit_fail("missing_path", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "missing path"}
        }.dump());
        return;
    }

    std::string rel_norm;
    std::string nerr;
    if (!pqnas::normalize_user_rel_path_strict(rel_path, &rel_norm, &nerr)) {
        audit_fail("invalid_path", 400, nerr);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid path"}
        }.dump());
        return;
    }

    auto* plm = pqnas::get_path_lock_manager();
    auto write_guard = plm->lock_paths(fp_hex, {rel_norm});

    const std::filesystem::path user_dir = user_dir_for_fp(users, fp_hex);

    pqnas::ResolvedLogicalItem item;
    std::string rerr;
    if (!pqnas::resolve_existing_user_item(users, fp_hex, rel_norm, &item, &rerr) || !item.exists) {
        audit_fail("not_found", 404, rerr);
        reply_json(res, 404, json{
            {"ok", false},
            {"error", "not_found"},
            {"message", "path not found"}
        }.dump());
        return;
    }

    auto* idx = pqnas::get_file_location_index();
    if (!idx) {
        audit_fail("metadata_index_missing", 500);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "metadata index missing"}
        }.dump());
        return;
    }

    auto file_size_safe = [&](const std::filesystem::path& p) -> std::uint64_t {
        std::error_code ec;
        auto sz = std::filesystem::file_size(p, ec);
        return ec ? 0 : static_cast<std::uint64_t>(sz);
    };

    if (item.is_file) {
        if (!item.has_physical_anchor) {
            audit_fail("file_missing_physical_anchor", 500);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "file missing physical anchor"}
            }.dump());
            return;
        }

        const std::filesystem::path abs_path = item.abs_path;

        if (abs_path == user_dir) {
            audit_fail("refuse_root_delete", 400);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "refusing to delete root"}
            }.dump());
            return;
        }

        std::error_code ec;
        auto st = std::filesystem::symlink_status(abs_path, ec);
        if (ec || !std::filesystem::exists(st)) {
            audit_fail("not_found", 404);
            reply_json(res, 404, json{
                {"ok", false},
                {"error", "not_found"},
                {"message", "path not found"}
            }.dump());
            return;
        }

        if (std::filesystem::is_symlink(st)) {
            audit_fail("symlink_not_supported", 400);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "symlinks not supported"}
            }.dump());
            return;
        }

        if (!std::filesystem::is_regular_file(st)) {
            audit_fail("path_not_file", 400);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "path is not a file"}
            }.dump());
            return;
        }

        const std::uint64_t freed_bytes = file_size_safe(abs_path);

        ec.clear();
        auto st2 = std::filesystem::symlink_status(abs_path, ec);
        if (ec || !std::filesystem::exists(st2)) {
            audit_fail("not_found", 404);
            reply_json(res, 404, json{
                {"ok", false},
                {"error", "not_found"},
                {"message", "path not found"}
            }.dump());
            return;
        }

        if (std::filesystem::is_symlink(st2)) {
            audit_fail("symlink_not_supported", 400);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "symlinks not supported"}
            }.dump());
            return;
        }

        if (!std::filesystem::is_regular_file(st2)) {
            audit_fail("path_changed_before_delete", 409);
            reply_json(res, 409, json{
                {"ok", false},
                {"error", "path_conflict"},
                {"message", "path changed before delete"}
            }.dump());
            return;
        }

        const std::string pool_id = u.storage_pool_id.empty() ? "default" : u.storage_pool_id;
        const std::filesystem::path storage_root = data_root_for_pool_id(pool_id);

        std::string merr;
        auto mrec = idx->get(fp_hex, rel_norm, &merr);
        if (!merr.empty()) {
            audit_fail("metadata_lookup_failed", 500, merr);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "failed to read metadata before trash move"},
                {"detail", pqnas::shorten(merr, 180)}
            }.dump());
            return;
        }

        std::string terr;

        pqnas::TrashService::MoveToTrashParams tp;
        tp.scope_type = "user";
        tp.scope_id = fp_hex;
        tp.deleted_by_fp = fp_hex;
        tp.origin_app = "filemgr";
        tp.item_type = "file";
        tp.original_rel_path = rel_norm;
        tp.payload_abs_path = abs_path;
        tp.storage_root = storage_root;
        tp.size_bytes = freed_bytes;
        tp.file_count = 1;

        if (mrec.has_value()) {
            tp.source_pool = mrec->current_pool;
            tp.source_tier_state = mrec->tier_state;
        }

        pqnas::TrashService::MoveToTrashResult tr;
        if (!trash_service.move_to_trash(tp, &tr, &terr)) {
            audit_fail("trash_move_failed", 500, terr);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "failed to move item to trash"},
                {"detail", pqnas::shorten(terr, 180)}
            }.dump());
            return;
        }

        {
            std::string derr;
            if (!idx->erase(fp_hex, rel_norm, &derr)) {
                audit_fail("metadata_erase_failed", 500, derr);
                reply_json(res, 500, json{
                    {"ok", false},
                    {"error", "server_error"},
                    {"message", "delete metadata cleanup failed"},
                    {"detail", pqnas::shorten(derr, 180)}
                }.dump());
                return;
            }
        }

        {
            std::string ferr;
            if (!pqnas::favorites_remove_under_prefix(user_dir, rel_norm, "file", &ferr)) {
                audit_warn("favorites_cleanup_failed", ferr, rel_norm);
            }
        }
        {
            std::string gerr;
            if (auto* gidx = pqnas::get_gallery_meta_index()) {
                if (!gidx->erase_subtree("user", fp_hex, rel_norm, &gerr)) {
                    audit_warn("gallery_meta_cleanup_failed", gerr, rel_norm);
                }
            }
        }

        audit_ok(rel_path, "file", freed_bytes);
        reply_json(res, 200, json{
            {"ok", true},
            {"fingerprint_hex", fp_hex},
            {"path", rel_path},
            {"type", "file"},
            {"freed_bytes", freed_bytes},
            {"trash_id", tr.trash_id}
        }.dump());
        return;
    }

    if (item.is_dir) {
        std::string lerr;
        auto subtree_rows = idx->list_subtree_records(fp_hex, rel_norm, &lerr);
        if (!lerr.empty()) {
            audit_fail("metadata_subtree_list_failed", 500, lerr);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "failed to list metadata subtree"},
                {"detail", pqnas::shorten(lerr, 180)}
            }.dump());
            return;
        }

        if (subtree_rows.empty()) {
            if (!item.has_physical_anchor) {
                audit_fail("not_found", 404);
                reply_json(res, 404, json{
                    {"ok", false},
                    {"error", "not_found"},
                    {"message", "path not found"}
                }.dump());
                return;
            }

            const std::filesystem::path abs_path = item.abs_path;
            if (abs_path == user_dir) {
                audit_fail("refuse_root_delete", 400);
                reply_json(res, 400, json{
                    {"ok", false},
                    {"error", "bad_request"},
                    {"message", "refusing to delete root"}
                }.dump());
                return;
            }

            std::uint64_t freed_bytes = 0;
            std::uint64_t file_count = 0;
            std::error_code ec;

            auto root_st = std::filesystem::symlink_status(abs_path, ec);
            if (ec || !std::filesystem::exists(root_st)) {
                audit_fail("not_found", 404);
                reply_json(res, 404, json{
                    {"ok", false},
                    {"error", "not_found"},
                    {"message", "path not found"}
                }.dump());
                return;
            }

            if (std::filesystem::is_symlink(root_st)) {
                audit_fail("symlink_not_supported", 400);
                reply_json(res, 400, json{
                    {"ok", false},
                    {"error", "bad_request"},
                    {"message", "symlinks not supported"}
                }.dump());
                return;
            }

            if (!std::filesystem::is_directory(root_st)) {
                audit_fail("path_not_dir", 400);
                reply_json(res, 400, json{
                    {"ok", false},
                    {"error", "bad_request"},
                    {"message", "path is not a directory"}
                }.dump());
                return;
            }

            for (std::filesystem::recursive_directory_iterator it(
                     abs_path, std::filesystem::directory_options::skip_permission_denied, ec), end;
                 it != end && !ec;
                 it.increment(ec)) {
                std::error_code ec2;
                auto ent_st = std::filesystem::symlink_status(it->path(), ec2);
                if (ec2) {
                    audit_fail("tree_stat_failed", 500, ec2.message());
                    reply_json(res, 500, json{
                        {"ok", false},
                        {"error", "server_error"},
                        {"message", "delete scan failed"},
                        {"detail", pqnas::shorten(ec2.message(), 180)}
                    }.dump());
                    return;
                }

                if (std::filesystem::is_symlink(ent_st)) {
                    audit_fail("tree_contains_symlink", 409, it->path().string());
                    reply_json(res, 409, json{
                        {"ok", false},
                        {"error", "path_conflict"},
                        {"message", "directory contains symlinks"}
                    }.dump());
                    return;
                }

                if (std::filesystem::is_regular_file(ent_st)) {
                    std::error_code ec3;
                    auto sz = std::filesystem::file_size(it->path(), ec3);
                    if (ec3) {
                        audit_fail("file_size_failed", 500, ec3.message());
                        reply_json(res, 500, json{
                            {"ok", false},
                            {"error", "server_error"},
                            {"message", "delete scan failed"},
                            {"detail", pqnas::shorten(ec3.message(), 180)}
                        }.dump());
                        return;
                    }
                    ++file_count;
                    freed_bytes += static_cast<std::uint64_t>(sz);
                }
            }

            if (ec) {
                audit_fail("tree_walk_failed", 500, ec.message());
                reply_json(res, 500, json{
                    {"ok", false},
                    {"error", "server_error"},
                    {"message", "delete scan failed"},
                    {"detail", pqnas::shorten(ec.message(), 180)}
                }.dump());
                return;
            }

            ec.clear();
            auto root_st2 = std::filesystem::symlink_status(abs_path, ec);
            if (ec || !std::filesystem::exists(root_st2)) {
                audit_fail("not_found", 404);
                reply_json(res, 404, json{
                    {"ok", false},
                    {"error", "not_found"},
                    {"message", "path not found"}
                }.dump());
                return;
            }

            if (std::filesystem::is_symlink(root_st2)) {
                audit_fail("symlink_not_supported", 400);
                reply_json(res, 400, json{
                    {"ok", false},
                    {"error", "bad_request"},
                    {"message", "symlinks not supported"}
                }.dump());
                return;
            }

            if (!std::filesystem::is_directory(root_st2)) {
                audit_fail("path_changed_before_delete", 409);
                reply_json(res, 409, json{
                    {"ok", false},
                    {"error", "path_conflict"},
                    {"message", "path changed before delete"}
                }.dump());
                return;
            }

            const std::string pool_id = u.storage_pool_id.empty() ? "default" : u.storage_pool_id;
            const std::filesystem::path storage_root = data_root_for_pool_id(pool_id);

            std::string terr;

            pqnas::TrashService::MoveToTrashParams tp;
            tp.scope_type = "user";
            tp.scope_id = fp_hex;
            tp.deleted_by_fp = fp_hex;
            tp.origin_app = "filemgr";
            tp.item_type = "dir";
            tp.original_rel_path = rel_norm;
            tp.payload_abs_path = abs_path;
            tp.storage_root = storage_root;
            tp.size_bytes = freed_bytes;
            tp.file_count = file_count;

            pqnas::TrashService::MoveToTrashResult tr;
            if (!trash_service.move_to_trash(tp, &tr, &terr)) {
                audit_fail("trash_move_failed", 500, terr);
                reply_json(res, 500, json{
                    {"ok", false},
                    {"error", "server_error"},
                    {"message", "failed to move directory to trash"},
                    {"detail", pqnas::shorten(terr, 180)}
                }.dump());
                return;
            }

            {
                std::string ferr;
                if (!pqnas::favorites_remove_under_prefix(user_dir, rel_norm, "dir", &ferr)) {
                    audit_warn("favorites_cleanup_failed", ferr, rel_norm);
                }
            }
            {
                std::string gerr;
                if (auto* gidx = pqnas::get_gallery_meta_index()) {
                    if (!gidx->erase_subtree("user", fp_hex, rel_norm, &gerr)) {
                        audit_warn("gallery_meta_cleanup_failed", gerr, rel_norm);
                    }
                }
            }

            audit_ok(rel_path, "dir", freed_bytes);
            reply_json(res, 200, json{
                {"ok", true},
                {"fingerprint_hex", fp_hex},
                {"path", rel_path},
                {"type", "dir"},
                {"freed_bytes", freed_bytes},
                {"trash_id", tr.trash_id}
            }.dump());
            return;
        }

        std::filesystem::path dir_abs;
        bool have_root = false;

        if (!subtree_rows.empty()) {
            const auto& first = subtree_rows.front();
            std::filesystem::path root = std::filesystem::path(first.physical_path);
            for (const auto& _ : std::filesystem::path(first.logical_rel_path)) {
                (void)_;
                root = root.parent_path();
            }
            dir_abs = root / std::filesystem::path(rel_norm);
            have_root = true;
        } else if (item.has_physical_anchor) {
            dir_abs = item.abs_path;
            have_root = true;
        }

        if (!have_root || dir_abs == user_dir) {
            audit_fail("refuse_root_delete", 400);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "refusing to delete root"}
            }.dump());
            return;
        }

        const std::string dir_root_s = dir_abs.lexically_normal().string();
        bool all_under_root = true;
        std::uint64_t freed_bytes = 0;
        const std::uint64_t file_count = static_cast<std::uint64_t>(subtree_rows.size());

        for (const auto& rec : subtree_rows) {
            const std::filesystem::path phys = std::filesystem::path(rec.physical_path).lexically_normal();
            const std::string phys_s = phys.string();

            if (phys_s != dir_root_s && phys_s.rfind(dir_root_s + "/", 0) != 0) {
                all_under_root = false;
                break;
            }
            freed_bytes += rec.size_bytes;
        }

        if (!all_under_root) {
            audit_fail("dir_delete_cross_root_unsupported", 409);
            reply_json(res, 409, json{
                {"ok", false},
                {"error", "unsupported"},
                {"message", "directory delete across mixed storage roots not supported yet"}
            }.dump());
            return;
        }

        std::error_code ec;

        auto dir_st = std::filesystem::symlink_status(dir_abs, ec);
        if (ec || !std::filesystem::exists(dir_st)) {
            audit_fail("not_found", 404);
            reply_json(res, 404, json{
                {"ok", false},
                {"error", "not_found"},
                {"message", "path not found"}
            }.dump());
            return;
        }

        if (std::filesystem::is_symlink(dir_st)) {
            audit_fail("symlink_not_supported", 400);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "symlinks not supported"}
            }.dump());
            return;
        }

        if (!std::filesystem::is_directory(dir_st)) {
            audit_fail("path_not_dir", 400);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "path is not a directory"}
            }.dump());
            return;
        }

        for (std::filesystem::recursive_directory_iterator it(
                 dir_abs, std::filesystem::directory_options::skip_permission_denied, ec), end;
             it != end && !ec;
             it.increment(ec)) {
            std::error_code ec2;
            auto ent_st = std::filesystem::symlink_status(it->path(), ec2);
            if (ec2) {
                audit_fail("tree_stat_failed", 500, ec2.message());
                reply_json(res, 500, json{
                    {"ok", false},
                    {"error", "server_error"},
                    {"message", "delete scan failed"},
                    {"detail", pqnas::shorten(ec2.message(), 180)}
                }.dump());
                return;
            }

            if (std::filesystem::is_symlink(ent_st)) {
                audit_fail("tree_contains_symlink", 409, it->path().string());
                reply_json(res, 409, json{
                    {"ok", false},
                    {"error", "path_conflict"},
                    {"message", "directory contains symlinks"}
                }.dump());
                return;
            }
        }

        if (ec) {
            audit_fail("tree_walk_failed", 500, ec.message());
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "delete scan failed"},
                {"detail", pqnas::shorten(ec.message(), 180)}
            }.dump());
            return;
        }

        ec.clear();
        auto dir_st2 = std::filesystem::symlink_status(dir_abs, ec);
        if (ec || !std::filesystem::exists(dir_st2)) {
            audit_fail("not_found", 404);
            reply_json(res, 404, json{
                {"ok", false},
                {"error", "not_found"},
                {"message", "path not found"}
            }.dump());
            return;
        }

        if (std::filesystem::is_symlink(dir_st2)) {
            audit_fail("symlink_not_supported", 400);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "symlinks not supported"}
            }.dump());
            return;
        }

        if (!std::filesystem::is_directory(dir_st2)) {
            audit_fail("path_changed_before_delete", 409);
            reply_json(res, 409, json{
                {"ok", false},
                {"error", "path_conflict"},
                {"message", "path changed before delete"}
            }.dump());
            return;
        }

        const std::string pool_id = u.storage_pool_id.empty() ? "default" : u.storage_pool_id;
        const std::filesystem::path storage_root = data_root_for_pool_id(pool_id);

        std::string terr;

        pqnas::TrashService::MoveToTrashParams tp;
        tp.scope_type = "user";
        tp.scope_id = fp_hex;
        tp.deleted_by_fp = fp_hex;
        tp.origin_app = "filemgr";
        tp.item_type = "dir";
        tp.original_rel_path = rel_norm;
        tp.payload_abs_path = dir_abs;
        tp.storage_root = storage_root;
        tp.size_bytes = freed_bytes;
        tp.file_count = file_count;

        if (!subtree_rows.empty()) {
            tp.source_pool = subtree_rows.front().current_pool;
            tp.source_tier_state = subtree_rows.front().tier_state;
        }

        pqnas::TrashService::MoveToTrashResult tr;
        if (!trash_service.move_to_trash(tp, &tr, &terr)) {
            audit_fail("trash_move_failed", 500, terr);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "failed to move directory to trash"},
                {"detail", pqnas::shorten(terr, 180)}
            }.dump());
            return;
        }

        {
            std::string derr;
            if (!idx->erase_subtree(fp_hex, rel_norm, &derr)) {
                audit_fail("metadata_erase_subtree_failed", 500, derr);
                reply_json(res, 500, json{
                    {"ok", false},
                    {"error", "server_error"},
                    {"message", "delete metadata cleanup failed"},
                    {"detail", pqnas::shorten(derr, 180)}
                }.dump());
                return;
            }
        }

        {
            std::string ferr;
            if (!pqnas::favorites_remove_under_prefix(user_dir, rel_norm, "dir", &ferr)) {
                audit_warn("favorites_cleanup_failed", ferr, rel_norm);
            }
        }
        {
            std::string gerr;
            if (auto* gidx = pqnas::get_gallery_meta_index()) {
                if (!gidx->erase_subtree("user", fp_hex, rel_norm, &gerr)) {
                    audit_warn("gallery_meta_cleanup_failed", gerr, rel_norm);
                }
            }
        }

        audit_ok(rel_path, "dir", freed_bytes);
        reply_json(res, 200, json{
            {"ok", true},
            {"fingerprint_hex", fp_hex},
            {"path", rel_path},
            {"type", "dir"},
            {"freed_bytes", freed_bytes},
            {"trash_id", tr.trash_id}
        }.dump());
        return;
    }

    audit_fail("unsupported_type", 400);
    reply_json(res, 400, json{
        {"ok", false},
        {"error", "bad_request"},
        {"message", "unsupported path type"}
    }.dump());
});

// GET /api/v4/files/list?path=relative/dir   (path optional; empty => user root)
// Response: JSON listing of immediate children (no recursion)
srv.Get("/api/v4/files/list", [&](const httplib::Request& req, httplib::Response& res) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;

    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto audit_fail = [&](const std::string& reason, int http, const std::string& detail = "") {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_list_fail";
        ev.outcome = "fail";
        ev.f["fingerprint"] = fp_hex;
        ev.f["reason"] = reason;
        ev.f["http"] = std::to_string(http);
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);

        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    auto audit_ok = [&](const std::string& rel_dir, std::size_t count) {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_list_ok";
        ev.outcome = "ok";
        ev.f["fingerprint"] = fp_hex;
        ev.f["path"] = pqnas::shorten(rel_dir, 200);
        ev.f["count"] = std::to_string((unsigned long long)count);

        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    // Storage allocated check (fail-closed)
    {
        auto uopt = users.get(fp_hex);
        if (!uopt.has_value()) {
            audit_fail("user_missing", 403);
            reply_json(res, 403, json{{"ok", false}, {"error", "forbidden"}, {"message", "policy denied"}}.dump());
            return;
        }
        const auto& u = *uopt;
        if (u.storage_state != "allocated") {
            audit_fail("storage_unallocated", 403);
            reply_json(res, 403, json{
                {"ok", false},
                {"error", "storage_unallocated"},
                {"message", "Storage not allocated"},
                {"fingerprint_hex", fp_hex},
                {"quota_bytes", u.quota_bytes}
            }.dump());
            return;
        }
    }

    // path param (optional). Empty => root listing.
    std::string rel_dir;
    if (req.has_param("path")) rel_dir = req.get_param_value("path");

    const std::filesystem::path user_dir = user_dir_for_fp(users, fp_hex);
    std::filesystem::path abs_dir = user_dir;
    std::string rel_dir_norm;

    if (!rel_dir.empty()) {
        std::string nerr;
        if (!pqnas::normalize_user_rel_path_strict(rel_dir, &rel_dir_norm, &nerr)) {
            audit_fail("invalid_path", 400, nerr);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "invalid path"}
            }.dump());
            return;
        }

        // Physical tree is still resolved from legacy visible root.
        std::string perr;
        if (!pqnas::resolve_user_path_strict(user_dir, rel_dir_norm, &abs_dir, &perr)) {
            // Do NOT fail yet. Directory may exist only logically via metadata.
            abs_dir.clear();
        }
    }

    auto is_reserved_name = [&](const std::string& name) -> bool {
        return name == ".pqnas";
    };

    struct ListedItem {
        std::string name;
        std::string type;
        std::uint64_t size_bytes = 0;
        long long mtime_unix = 0;
    };

    std::map<std::string, ListedItem> merged;

    // 1) Legacy filesystem children under current visible directory, if physical dir exists.
    // Symlinks are never followed here: a symlinked listed directory is rejected,
    // and symlink children are skipped entirely.
    bool legacy_dir_ok = false;
    {
        std::error_code ec;
        std::filesystem::path dir_to_check = abs_dir.empty() ? user_dir : abs_dir;
        auto st = std::filesystem::symlink_status(dir_to_check, ec);

        if (!ec && std::filesystem::exists(st)) {
            if (std::filesystem::is_symlink(st)) {
                audit_fail("symlink_not_supported", 400);
                reply_json(res, 400, json{
                    {"ok", false},
                    {"error", "bad_request"},
                    {"message", "symlinks not supported"}
                }.dump());
                return;
            }

            if (std::filesystem::is_directory(st)) {
                legacy_dir_ok = true;

                for (std::filesystem::directory_iterator it(dir_to_check, ec), end; it != end && !ec; it.increment(ec)) {
                    std::error_code ec2;

                    const auto child_path = it->path();
                    const auto name = child_path.filename().string();
                    if (name == "." || name == ".." || name.empty()) continue;
                    if (is_reserved_name(name)) continue;

                    auto child_st = std::filesystem::symlink_status(child_path, ec2);
                    if (ec2) continue;

                    if (std::filesystem::is_symlink(child_st)) {
                        continue;
                    }

                    std::string type = "other";
                    if (std::filesystem::is_directory(child_st)) {
                        type = "dir";
                    } else if (std::filesystem::is_regular_file(child_st)) {
                        type = "file";
                    } else {
                        continue;
                    }

                    std::uint64_t size_bytes = 0;
                    if (type == "file") {
                        ec2.clear();
                        auto sz = std::filesystem::file_size(child_path, ec2);
                        if (!ec2) size_bytes = static_cast<std::uint64_t>(sz);
                    }

                    long long mtime_unix = 0;
                    ec2.clear();
                    auto ft = std::filesystem::last_write_time(child_path, ec2);
                    if (!ec2) {
                        using namespace std::chrono;
                        auto sctp = time_point_cast<system_clock::duration>(
                            ft - decltype(ft)::clock::now() + system_clock::now()
                        );
                        mtime_unix = (long long)duration_cast<seconds>(sctp.time_since_epoch()).count();
                    }

                    merged[name] = ListedItem{
                        name,
                        type,
                        size_bytes,
                        mtime_unix
                    };
                }
            }
        }
    }

    // 2) Merge metadata-backed immediate children.
    bool metadata_ok = false;
    if (auto* idx = pqnas::get_file_location_index()) {
        std::string lerr;
        auto rows = idx->list_immediate_children(fp_hex, rel_dir_norm, &lerr);
        if (!lerr.empty()) {
            audit_fail("metadata_list_failed", 500, lerr);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "metadata list failed"},
                {"detail", pqnas::shorten(lerr, 180)}
            }.dump());
            return;
        }

        if (!rows.empty()) metadata_ok = true;

        for (const auto& rec : rows) {
            if (rec.name.empty()) continue;
            if (is_reserved_name(rec.name)) continue;

            auto mit = merged.find(rec.name);
            if (mit == merged.end()) {
                merged[rec.name] = ListedItem{
                    rec.name,
                    rec.type.empty() ? "file" : rec.type,
                    rec.type == "file" ? rec.size_bytes : 0,
                    (long long)rec.mtime_epoch
                };
            } else {
                // Metadata wins over legacy for files and dirs.
                mit->second.type = rec.type.empty() ? mit->second.type : rec.type;
                if (mit->second.type == "file") {
                    mit->second.size_bytes = rec.size_bytes;
                } else {
                    mit->second.size_bytes = 0;
                }
                mit->second.mtime_unix = (long long)rec.mtime_epoch;
            }
        }
    }

    // If neither physical dir nor metadata children exist, report not found for non-root paths.
    if (!legacy_dir_ok && !metadata_ok && !rel_dir_norm.empty()) {
        audit_fail("not_found", 404);
        reply_json(res, 404, json{
            {"ok", false},
            {"error", "not_found"},
            {"message", "directory not found"}
        }.dump());
        return;
    }

    json out;
    out["ok"] = true;
    out["fingerprint_hex"] = fp_hex;
    out["path"] = rel_dir_norm.empty() ? rel_dir : rel_dir_norm;
    out["items"] = json::array();

    std::size_t count = 0;
    for (const auto& kv : merged) {
        out["items"].push_back(json{
            {"name", kv.second.name},
            {"type", kv.second.type},
            {"size_bytes", kv.second.size_bytes},
            {"mtime_unix", kv.second.mtime_unix}
        });
        count++;
        if (count >= 5000) break;
    }

    audit_ok(rel_dir_norm.empty() ? rel_dir : rel_dir_norm, count);
    reply_json(res, 200, out.dump());
});
    // GET /api/v4/me/storage   (user/admin)
// Purpose: UI-friendly storage/quota summary for the *current* user.
// - Soft UI: filemgr can poll this and show warnings at 80%/90%
// - Does NOT expose mountpoints; only user dir usage.
//
// Response example:
// {
//   "ok": true,
//   "fingerprint_hex": "...",
//   "role": "user",
//   "storage_state": "allocated",
//   "quota_bytes": 10737418240,
//   "used_bytes": 123456789,
//   "used_percent": 1.149,
//   "warn_level": "ok"|"warn"|"crit",
//   "scanned_entries": 1234,
//   "partial": false,
//   "ts": "..."
// }
srv.Get("/api/v4/me/storage", [&](const httplib::Request& req, httplib::Response& res) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;

    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto audit_ok = [&](const json& extra) {
        pqnas::AuditEvent ev;
        ev.event = "v4.me_storage_ok";
        ev.outcome = "ok";
        ev.f["fingerprint"] = fp_hex;
        ev.f["role"] = role;
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();

        // Optional small extras
        try {
            if (extra.contains("storage_state")) ev.f["storage_state"] = pqnas::shorten(extra["storage_state"].get<std::string>(), 40);
            if (extra.contains("warn_level"))    ev.f["warn_level"]    = pqnas::shorten(extra["warn_level"].get<std::string>(), 16);
            if (extra.contains("partial"))       ev.f["partial"]       = extra["partial"].get<bool>() ? "true" : "false";
        } catch (...) {}

        audit_append(ev);
    };

    auto audit_fail = [&](const std::string& reason, int http, const std::string& detail = "") {
        pqnas::AuditEvent ev;
        ev.event = "v4.me_storage_fail";
        ev.outcome = "fail";
        ev.f["fingerprint"] = fp_hex;
        ev.f["role"] = role;
        ev.f["reason"] = reason;
        ev.f["http"] = std::to_string(http);
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);

        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    // UsersRegistry lookup (fail-closed)
    auto uopt = users.get(fp_hex);
    if (!uopt.has_value()) {
        audit_fail("user_missing", 403);
        reply_json(res, 403, json{
            {"ok", false},
            {"error", "forbidden"},
            {"message", "policy denied"}
        }.dump());
        return;
    }
    const auto& u = *uopt;

    const std::string now_iso = now_iso_utc();
    const std::filesystem::path user_dir = user_dir_for_fp(users, fp_hex);

    json out;
    out["ok"] = true;
    out["fingerprint_hex"] = fp_hex;
    out["role"] = role;
    out["storage_state"] = u.storage_state.empty() ? "" : u.storage_state;
    out["quota_bytes"] = (std::uint64_t)u.quota_bytes;
    out["used_bytes"] = (std::uint64_t)0;
    out["used_percent"] = 0.0;
    out["warn_level"] = "ok";
    out["partial"] = false;
    out["scanned_entries"] = 0;
    out["ts"] = now_iso;

    // If not allocated, return ok:true (UI uses this to show friendly state).
    if (u.storage_state != "allocated") {
        audit_ok(out);
        reply_json(res, 200, out.dump());
        return;
    }

    // Best-effort: scan user_dir recursively for used_bytes.
    // Caps keep it safe for huge trees.
    const std::uint64_t ENTRY_CAP = 250000;  // max files/dirs visited
    const long long TIME_CAP_MS   = 250;     // soft time cap

    std::uint64_t used = 0;
    std::uint64_t entries = 0;
    bool partial = false;

    std::error_code ec;
    auto st = std::filesystem::status(user_dir, ec);
    if (ec || !std::filesystem::exists(st) || !std::filesystem::is_directory(st)) {
        // allocated but directory missing => treat as 0 used, but mark partial + warn
        out["used_bytes"] = (std::uint64_t)0;
        out["partial"] = true;
        out["warn_level"] = "warn";
        out["note"] = "user_dir_missing_or_not_dir";
        audit_ok(out);
        reply_json(res, 200, out.dump());
        return;
    }

    const auto t0 = std::chrono::steady_clock::now();

    std::filesystem::recursive_directory_iterator it(
        user_dir,
        std::filesystem::directory_options::skip_permission_denied,
        ec
    );
    std::filesystem::recursive_directory_iterator end;

    for (; it != end && !ec; it.increment(ec)) {
        entries++;
        if (entries >= ENTRY_CAP) { partial = true; break; }

        const auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::steady_clock::now() - t0
        ).count();
        if (elapsed >= TIME_CAP_MS) { partial = true; break; }

        std::error_code ec2;
        if (it->is_regular_file(ec2) && !ec2) {
            ec2.clear();
            auto sz = it->file_size(ec2);
            if (!ec2) used += (std::uint64_t)sz;
        }
    }
    if (ec) partial = true;

    out["used_bytes"] = (std::uint64_t)used;
    out["scanned_entries"] = (std::uint64_t)entries;
    out["partial"] = partial;

    // used_percent (quota==0 => define as 0, but warn if used>0)
    double pct = 0.0;
    if (u.quota_bytes > 0) {
        pct = (double)used * 100.0 / (double)u.quota_bytes;
    } else {
        pct = (used > 0) ? 100.0 : 0.0;
    }
    out["used_percent"] = pct;

    // Soft warning levels (tune as you like)
    // - warn >= 80%
    // - crit >= 90%
    std::string lvl = "ok";
    if (pct >= 90.0) lvl = "crit";
    else if (pct >= 80.0) lvl = "warn";
    if (partial && lvl == "ok") lvl = "warn"; // partial scan => at least warn
    out["warn_level"] = lvl;

    audit_ok(out);
    reply_json(res, 200, out.dump());
});

    // POST /api/v4/files/exists?path=rel/path
srv.Post("/api/v4/files/exists", [&](const httplib::Request& req, httplib::Response& res) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;

    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto add_ip_headers = [&](pqnas::AuditEvent& ev) {
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
    };

    auto audit_fail = [&](const std::string& reason, int http, const std::string& detail = "",
                          const std::string& path_rel = "") {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_exists_fail";
        ev.outcome = "fail";
        ev.f["fingerprint"] = fp_hex;
        ev.f["reason"] = reason;
        ev.f["http"] = std::to_string(http);
        if (!path_rel.empty()) ev.f["path"] = pqnas::shorten(path_rel, 200);
        if (!detail.empty())   ev.f["detail"] = pqnas::shorten(detail, 180);

        add_ip_headers(ev);
        audit_append(ev);
    };

    auto audit_ok = [&](const std::string& path_rel,
                        const std::string& type,
                        bool exists,
                        std::uint64_t bytes) {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_exists_ok";
        ev.outcome = "ok";
        ev.f["fingerprint"] = fp_hex;
        ev.f["path"] = pqnas::shorten(path_rel, 200);
        ev.f["exists"] = exists ? "1" : "0";
        ev.f["type"] = type;
        if (exists && type == "file") ev.f["bytes"] = std::to_string((unsigned long long)bytes);

        add_ip_headers(ev);
        audit_append(ev);
    };

    // must have allocated storage
    auto uopt = users.get(fp_hex);
    if (!uopt.has_value() || uopt->storage_state != "allocated") {
        audit_fail("storage_unallocated", 403);
        reply_json(res, 403, json{
            {"ok", false},
            {"error", "storage_unallocated"},
            {"message", "Storage not allocated"}
        }.dump());
        return;
    }

    std::string path_rel;
    if (req.has_param("path")) path_rel = req.get_param_value("path");

    if (path_rel.empty()) {
        audit_fail("missing_path", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "missing path"}
        }.dump());
        return;
    }

pqnas::ResolvedExistingPath rp;
std::string err;
if (!pqnas::resolve_existing_user_file_path(users, fp_hex, path_rel, &rp, &err)) {
    // Distinguish invalid path from just "not found"
    std::string rel_norm;
    std::string nerr;
    if (!pqnas::normalize_user_rel_path_strict(path_rel, &rel_norm, &nerr)) {
        audit_fail("invalid_path", 400, nerr, path_rel);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid path"}
        }.dump());
        return;
    }

    audit_ok(path_rel, "missing", false, 0);
    reply_json(res, 200, json{
        {"ok", true},
        {"path", path_rel},
        {"exists", false},
        {"type", "missing"},
        {"bytes", 0}
    }.dump());
    return;
}

    const std::filesystem::path path_abs = rp.abs_path;

    // Never trust a path that traverses an existing symlinked parent chain.
    {
        std::string serr;
        if (!ensure_no_symlink_in_existing_path_prefix(path_abs, &serr)) {
            audit_ok(path_rel, "missing", false, 0);
            reply_json(res, 200, json{
                {"ok", true},
                {"path", path_rel},
                {"exists", false},
                {"type", "missing"},
                {"bytes", 0}
            }.dump());
            return;
        }
    }

    std::error_code ec;
    auto st = std::filesystem::symlink_status(path_abs, ec);

    bool exists = (!ec && std::filesystem::exists(st));

    std::string type = "missing";
    std::uint64_t bytes = 0;

    if (exists) {
        if (std::filesystem::is_symlink(st)) {
            exists = false;
            type = "missing";
        } else if (std::filesystem::is_regular_file(st)) {
            type = "file";
            bytes = pqnas::file_size_u64_safe(path_abs);
        } else if (std::filesystem::is_directory(st)) {
            type = "dir";
        } else {
            type = "other";
        }
    }

    audit_ok(path_rel, type, exists, bytes);

    reply_json(res, 200, json{
        {"ok", true},
        {"path", path_rel},
        {"exists", exists},
        {"type", type},
        {"bytes", bytes}
    }.dump());
});


    // POST /api/v4/files/copy?from=old/path&to=new/path
srv.Post("/api/v4/files/copy", [&](const httplib::Request& req, httplib::Response& res) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;
    if (!require_same_origin_for_cookie_mutation(req, res)) return;
    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto add_ip_headers = [&](pqnas::AuditEvent& ev) {
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
    };

    auto audit_fail = [&](const std::string& reason, int http, const std::string& detail = "",
                          const std::string& from_rel = "", const std::string& to_rel = "") {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_copy_fail";
        ev.outcome = "fail";
        ev.f["fingerprint"] = fp_hex;
        ev.f["reason"] = reason;
        ev.f["http"] = std::to_string(http);
        if (!from_rel.empty()) ev.f["from"] = pqnas::shorten(from_rel, 200);
        if (!to_rel.empty())   ev.f["to"]   = pqnas::shorten(to_rel, 200);
        if (!detail.empty())   ev.f["detail"] = pqnas::shorten(detail, 180);

        add_ip_headers(ev);
        audit_append(ev);
    };

    auto audit_quota = [&](int http,
                           const std::string& detail,
                           const std::string& from_rel,
                           const std::string& to_rel,
                           std::uint64_t src_bytes,
                           std::uint64_t dst_old_bytes,
                           std::uint64_t delta_bytes) {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_copy_quota_exceeded";
        ev.outcome = "fail";
        ev.f["fingerprint"] = fp_hex;
        ev.f["reason"] = "quota_exceeded";
        ev.f["http"] = std::to_string(http);
        ev.f["from"] = pqnas::shorten(from_rel, 200);
        ev.f["to"]   = pqnas::shorten(to_rel, 200);
        ev.f["src_bytes"] = std::to_string((unsigned long long)src_bytes);
        ev.f["dst_old_bytes"] = std::to_string((unsigned long long)dst_old_bytes);
        ev.f["delta_bytes"] = std::to_string((unsigned long long)delta_bytes);
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);

        add_ip_headers(ev);
        audit_append(ev);
    };

    auto audit_ok = [&](const std::string& from_rel,
                        const std::string& to_rel,
                        std::uint64_t src_bytes,
                        std::uint64_t dst_old_bytes,
                        std::uint64_t delta_bytes,
                        bool overwrote) {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_copy_ok";
        ev.outcome = "ok";
        ev.f["fingerprint"] = fp_hex;
        ev.f["from"] = pqnas::shorten(from_rel, 200);
        ev.f["to"]   = pqnas::shorten(to_rel, 200);
        ev.f["type"] = "file";
        ev.f["src_bytes"] = std::to_string((unsigned long long)src_bytes);
        ev.f["dst_old_bytes"] = std::to_string((unsigned long long)dst_old_bytes);
        ev.f["delta_bytes"] = std::to_string((unsigned long long)delta_bytes);
        ev.f["overwrote"] = overwrote ? "1" : "0";

        add_ip_headers(ev);
        audit_append(ev);
    };

    // must have allocated storage
    auto uopt = users.get(fp_hex);
    if (!uopt.has_value() || uopt->storage_state != "allocated") {
        audit_fail("storage_unallocated", 403);
        reply_json(res, 403, json{
            {"ok", false},
            {"error", "storage_unallocated"},
            {"message", "Storage not allocated"}
        }.dump());
        return;
    }

    std::string from_rel, to_rel;
    if (req.has_param("from")) from_rel = req.get_param_value("from");
    if (req.has_param("to"))   to_rel   = req.get_param_value("to");

    if (from_rel.empty() || to_rel.empty()) {
        audit_fail("missing_from_or_to", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "missing from or to"}
        }.dump());
        return;
    }

	const std::filesystem::path user_dir = user_dir_for_fp(users, fp_hex);

	std::string from_rel_norm, to_rel_norm;
	std::string nerr1, nerr2;

	if (!pqnas::normalize_user_rel_path_strict(from_rel, &from_rel_norm, &nerr1)) {
    	audit_fail("invalid_from_path", 400, nerr1, from_rel, to_rel);
	    reply_json(res, 400, json{
    	    {"ok", false},
        	{"error", "bad_request"},
	        {"message", "invalid from path"}
    	}.dump());
    	return;
	}

	if (!pqnas::normalize_user_rel_path_strict(to_rel, &to_rel_norm, &nerr2)) {
    	audit_fail("invalid_to_path", 400, nerr2, from_rel, to_rel);
	    reply_json(res, 400, json{
    	    {"ok", false},
        	{"error", "bad_request"},
	        {"message", "invalid to path"}
    	}.dump());
    	return;
	}

	if (from_rel_norm == to_rel_norm) {
    	audit_fail("same_path", 400, "", from_rel, to_rel);
	    reply_json(res, 400, json{
    	    {"ok", false},
        	{"error", "bad_request"},
	        {"message", "from and to are the same"}
    	}.dump());
    	return;
	}

	auto* idx = pqnas::get_file_location_index();
	if (!idx) {
    	audit_fail("metadata_index_missing", 500, "", from_rel, to_rel);
	    reply_json(res, 500, json{
    	    {"ok", false},
        	{"error", "server_error"},
	        {"message", "metadata index missing"}
    	}.dump());
    	return;
	}

	// Resolve logical source exactly like move/stat-era code.
	pqnas::ResolvedLogicalItem src;
	std::string rerr;
	if (!pqnas::resolve_existing_user_item(users, fp_hex, from_rel_norm, &src, &rerr) || !src.exists) {
    	audit_fail("not_found", 404, rerr, from_rel, to_rel);
    	reply_json(res, 404, json{
        	{"ok", false},
        	{"error", "not_found"},
        	{"message", "source not found"}
	    }.dump());
    	return;
	}
	if (!src.is_file) {
    	audit_fail("src_not_file", 400, "", from_rel, to_rel);
	    reply_json(res, 400, json{
    	    {"ok", false},
        	{"error", "bad_request"},
	        {"message", "source must be a file (directories not supported yet)"}
    	}.dump());
    	return;
	}

	std::string gerr;
	auto src_rec = idx->get(fp_hex, from_rel_norm, &gerr);
	if (!src_rec.has_value()) {
	    audit_fail("metadata_source_missing", 500, gerr, from_rel, to_rel);
    	reply_json(res, 500, json{
        	{"ok", false},
	        {"error", "server_error"},
    	    {"message", "source metadata missing"},
        	{"detail", pqnas::shorten(gerr, 180)}
	    }.dump());
    	return;
	}

	const std::filesystem::path from_abs = src.abs_path;
	const std::filesystem::path old_phys = std::filesystem::path(src_rec->physical_path);
	const std::filesystem::path old_logical_path = std::filesystem::path(from_rel_norm);

	std::filesystem::path physical_root = old_phys;
	for (const auto& _ : old_logical_path) {
    	(void)_;
    	physical_root = physical_root.parent_path();
	}

	const std::filesystem::path to_abs = physical_root / std::filesystem::path(to_rel_norm);

	// Destination must not already exist logically.
	{
    	pqnas::ResolvedLogicalItem dst_existing;
	    std::string derr;
    	if (pqnas::resolve_existing_user_item(users, fp_hex, to_rel_norm, &dst_existing, &derr) &&
        	dst_existing.exists) {
	        audit_fail("dest_exists", 409, "", from_rel, to_rel);
    	    reply_json(res, 409, json{
        	    {"ok", false},
            	{"error", "dest_exists"},
            	{"message", "destination already exists"}
	        }.dump());
    	    return;
    	}
	}

    std::error_code ec;
    auto st_src = std::filesystem::symlink_status(from_abs, ec);
    if (ec || !std::filesystem::exists(st_src)) {
        audit_fail("not_found", 404, "", from_rel, to_rel);
        reply_json(res, 404, json{
            {"ok", false},
            {"error", "not_found"},
            {"message", "source not found"}
        }.dump());
        return;
    }

    if (std::filesystem::is_symlink(st_src)) {
        audit_fail("symlink_not_supported", 400, "", from_rel, to_rel);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "symlinks not supported"}
        }.dump());
        return;
    }

    if (!std::filesystem::is_regular_file(st_src)) {
        audit_fail("src_not_file", 400, "", from_rel, to_rel);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "source must be a file"}
        }.dump());
        return;
    }

    const std::uint64_t src_bytes = pqnas::file_size_u64_safe(from_abs);

    // Physical destination may or may not already exist; refuse symlinks.
    bool dst_exists = false;
    std::uint64_t dst_old_bytes = 0;

    ec.clear();
    auto st_dst = std::filesystem::symlink_status(to_abs, ec);
    if (ec) {
        if (ec != std::make_error_code(std::errc::no_such_file_or_directory)) {
            audit_fail("dest_stat_failed", 500, ec.message(), from_rel, to_rel);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "destination stat failed"},
                {"detail", pqnas::shorten(ec.message(), 180)}
            }.dump());
            return;
        }
        ec.clear();
    } else if (std::filesystem::exists(st_dst)) {
        dst_exists = true;

        if (std::filesystem::is_symlink(st_dst)) {
            audit_fail("symlink_not_supported", 400, "", from_rel, to_rel);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "symlinks not supported"}
            }.dump());
            return;
        }

        if (!std::filesystem::is_regular_file(st_dst)) {
            audit_fail("dst_not_file", 400, "", from_rel, to_rel);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "destination exists and is not a file"}
            }.dump());
            return;
        }

        dst_old_bytes = pqnas::file_size_u64_safe(to_abs);
    }

        auto ensure_no_symlink_dir_chain = [&](const std::filesystem::path& base,
                                           const std::filesystem::path& dir,
                                           bool require_exists,
                                           std::string* out_err) -> bool {
        if (out_err) out_err->clear();

        std::filesystem::path cur = base.lexically_normal();
        const std::filesystem::path target = dir.lexically_normal();

        std::error_code ec;
        auto base_st = std::filesystem::symlink_status(cur, ec);
        if (ec) {
            if (out_err) *out_err = "base symlink_status failed: " + ec.message();
            return false;
        }
        if (!std::filesystem::exists(base_st)) {
            if (out_err) *out_err = "base directory missing";
            return false;
        }
        if (std::filesystem::is_symlink(base_st)) {
            if (out_err) *out_err = "base directory is symlink";
            return false;
        }
        if (!std::filesystem::is_directory(base_st)) {
            if (out_err) *out_err = "base path is not a directory";
            return false;
        }

        const auto rel = target.lexically_relative(cur);
        if (rel.empty() || rel == ".") return true;

        for (const auto& part : rel) {
            if (part.empty()) continue;
            cur /= part;

            ec.clear();
            auto st = std::filesystem::symlink_status(cur, ec);
            if (ec) {
                if (out_err) *out_err = "symlink_status failed: " + ec.message();
                return false;
            }

            if (!std::filesystem::exists(st)) {
                if (require_exists) {
                    if (out_err) *out_err = "directory missing";
                    return false;
                }
                continue;
            }

            if (std::filesystem::is_symlink(st)) {
                if (out_err) *out_err = "directory chain contains symlink";
                return false;
            }

            if (!std::filesystem::is_directory(st)) {
                if (out_err) *out_err = "path component is not a directory";
                return false;
            }
        }

        return true;
    };

    const std::filesystem::path dst_parent = to_abs.parent_path();

    {
        std::string derr;
        if (!ensure_no_symlink_dir_chain(physical_root, dst_parent, false, &derr)) {
            audit_fail("dest_parent_invalid", 409, derr, from_rel, to_rel);
            reply_json(res, 409, json{
                {"ok", false},
                {"error", "path_conflict"},
                {"message", "destination parent path is invalid"},
                {"detail", pqnas::shorten(derr, 180)}
            }.dump());
            return;
        }
    }

    ec.clear();
    std::filesystem::create_directories(dst_parent, ec);
    if (ec) {
        audit_fail("mkdir_failed", 500, ec.message(), from_rel, to_rel);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "failed to create destination directories"},
            {"detail", pqnas::shorten(ec.message(), 180)}
        }.dump());
        return;
    }

    {
        std::string derr;
        if (!ensure_no_symlink_dir_chain(physical_root, dst_parent, true, &derr)) {
            audit_fail("dest_parent_invalid", 409, derr, from_rel, to_rel);
            reply_json(res, 409, json{
                {"ok", false},
                {"error", "path_conflict"},
                {"message", "destination parent path is invalid"},
                {"detail", pqnas::shorten(derr, 180)}
            }.dump());
            return;
        }
    }

    // quota-aware: delta = src_bytes - dst_old_bytes (only if positive)
    std::uint64_t delta_bytes = 0;
    if (src_bytes > dst_old_bytes) delta_bytes = (src_bytes - dst_old_bytes);

    if (delta_bytes > 0) {
        pqnas::QuotaCheckResult qc = pqnas::quota_check_for_upload_v1(
            users, fp_hex, user_dir, to_rel_norm, delta_bytes
        );
        if (!qc.ok) {
            if (qc.error == "storage_unallocated") {
                audit_fail("storage_unallocated", 403, "", from_rel, to_rel);
                reply_json(res, 403, json{
                    {"ok", false},
                    {"error", "storage_unallocated"},
                    {"message", "Storage not allocated"},
                    {"fingerprint_hex", fp_hex},
                    {"quota_bytes", qc.quota_bytes},
                    {"incoming_bytes", qc.incoming_bytes}
                }.dump());
                return;
            }

            if (qc.error == "invalid_path") {
                audit_fail("invalid_to_path", 400, "", from_rel, to_rel);
                reply_json(res, 400, json{
                    {"ok", false},
                    {"error", "bad_request"},
                    {"message", "invalid to path"}
                }.dump());
                return;
            }

            if (qc.error == "quota_exceeded") {
                const int http = 403;
                audit_quota(http, "", from_rel, to_rel, src_bytes, dst_old_bytes, delta_bytes);

                reply_json(res, http, json{
                    {"ok", false},
                    {"error", "quota_exceeded"},
                    {"message", "Quota exceeded"},
                    {"fingerprint_hex", fp_hex},
                    {"used_bytes", qc.used_bytes},
                    {"quota_bytes", qc.quota_bytes},
                    {"free_bytes", (qc.quota_bytes > qc.used_bytes ? (qc.quota_bytes - qc.used_bytes) : 0)},
                    {"incoming_bytes", qc.incoming_bytes},
                    {"existing_bytes", qc.existing_bytes},
                    {"would_used_bytes", qc.would_used_bytes}
                }.dump());
                return;
            }

            audit_fail("quota_check_failed", 403, qc.error, from_rel, to_rel);
            reply_json(res, 403, json{
                {"ok", false},
                {"error", "forbidden"},
                {"message", "policy denied"}
            }.dump());
            return;
        }
    }

    const std::filesystem::path tmp =
        dst_parent /
        (to_abs.filename().string() + ".tmp.copy." + random_b64url(12));

    ec.clear();
    {
        auto tmp_st = std::filesystem::symlink_status(tmp, ec);
        if (!ec && std::filesystem::exists(tmp_st)) {
            if (std::filesystem::is_symlink(tmp_st)) {
                audit_fail("tmp_is_symlink", 409, "", from_rel, to_rel);
                reply_json(res, 409, json{
                    {"ok", false},
                    {"error", "path_conflict"},
                    {"message", "temporary path is invalid"}
                }.dump());
                return;
            }
            std::filesystem::remove(tmp, ec);
        }
        ec.clear();
    }

    ec.clear();
    std::filesystem::copy_file(from_abs, tmp, std::filesystem::copy_options::overwrite_existing, ec);
    if (ec) {
        audit_fail("copy_failed", 500, ec.message(), from_rel, to_rel);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "copy failed"},
            {"detail", pqnas::shorten(ec.message(), 180)}
        }.dump());
        return;
    }

    if (dst_exists) {
        ec.clear();
        auto dst_st = std::filesystem::symlink_status(to_abs, ec);
        if (ec) {
            std::error_code ec2;
            std::filesystem::remove(tmp, ec2);

            audit_fail("dst_stat_failed", 500, ec.message(), from_rel, to_rel);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "destination stat failed"},
                {"detail", pqnas::shorten(ec.message(), 180)}
            }.dump());
            return;
        }

        if (!std::filesystem::exists(dst_st)) {
            dst_exists = false;
        } else {
            if (std::filesystem::is_symlink(dst_st)) {
                std::error_code ec2;
                std::filesystem::remove(tmp, ec2);

                audit_fail("dst_symlink_not_supported", 409, "", from_rel, to_rel);
                reply_json(res, 409, json{
                    {"ok", false},
                    {"error", "path_conflict"},
                    {"message", "destination exists and is not a regular file"}
                }.dump());
                return;
            }

            if (!std::filesystem::is_regular_file(dst_st)) {
                std::error_code ec2;
                std::filesystem::remove(tmp, ec2);

                audit_fail("dst_not_file", 400, "", from_rel, to_rel);
                reply_json(res, 400, json{
                    {"ok", false},
                    {"error", "bad_request"},
                    {"message", "destination exists and is not a file"}
                }.dump());
                return;
            }

            ec.clear();
            std::filesystem::remove(to_abs, ec);
            if (ec) {
                std::error_code ec2;
                std::filesystem::remove(tmp, ec2);

                audit_fail("overwrite_remove_failed", 500, ec.message(), from_rel, to_rel);
                reply_json(res, 500, json{
                    {"ok", false},
                    {"error", "server_error"},
                    {"message", "failed to overwrite destination"},
                    {"detail", pqnas::shorten(ec.message(), 180)}
                }.dump());
                return;
            }
        }
    }

    ec.clear();
    std::filesystem::rename(tmp, to_abs, ec);
    if (ec) {
        std::error_code ec2;
        std::filesystem::remove(tmp, ec2);

        audit_fail("rename_failed", 500, ec.message(), from_rel, to_rel);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "copy failed"},
            {"detail", pqnas::shorten(ec.message(), 180)}
        }.dump());
        return;
    }

	{
    	std::int64_t now_ts = now_epoch_sec();

	    std::error_code mec;
    	auto mtime_ft = std::filesystem::last_write_time(to_abs, mec);
	    std::int64_t mtime_epoch = now_ts;
    	if (!mec) {
        	using namespace std::chrono;
	        auto sctp = time_point_cast<system_clock::duration>(
    	        mtime_ft - std::filesystem::file_time_type::clock::now() + system_clock::now()
        	);
	        mtime_epoch = (std::int64_t)duration_cast<seconds>(sctp.time_since_epoch()).count();
    	}

	    pqnas::FileLocationRecord rec;
    	rec.fp = fp_hex;
	    rec.logical_rel_path = to_rel_norm;
    	rec.current_pool = src_rec->current_pool;
	    rec.physical_path = to_abs.string();
    	rec.tier_state = src_rec->tier_state;
	    rec.size_bytes = src_bytes;
    	rec.mtime_epoch = mtime_epoch;
	    rec.created_epoch = now_ts;
    	rec.updated_epoch = now_ts;
	    rec.version = 1;

    	std::string merr;
    	if (!idx->upsert_landing_file(rec, &merr)) {
        	std::error_code ec2;
	        std::filesystem::remove(to_abs, ec2);

    	    audit_fail("metadata_upsert_failed", 500, merr, from_rel, to_rel);
        	reply_json(res, 500, json{
            	{"ok", false},
	            {"error", "server_error"},
    	        {"message", "copy succeeded but metadata upsert failed"},
        	    {"detail", pqnas::shorten(merr, 180)}
	        }.dump());
    	    return;
    	}
	}

	audit_ok(from_rel, to_rel, src_bytes, dst_old_bytes, delta_bytes, dst_exists);

	reply_json(res, 200, json{
    	{"ok", true},
	    {"from", from_rel},
    	{"to", to_rel},
    	{"type", "file"},
	    {"src_bytes", src_bytes},
    	{"dst_old_bytes", dst_old_bytes},
	    {"delta_bytes", delta_bytes},
    	{"overwrote", dst_exists}
	}.dump());
});

// GET /api/v4/files/zip?path=relative/dir
// Response: application/zip (streams a zip of the directory)
srv.Get("/api/v4/files/zip", [&](const httplib::Request& req, httplib::Response& res) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;

    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto audit_fail = [&](const std::string& reason, int http, const std::string& detail = "") {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_zip_fail";
        ev.outcome = "fail";
        ev.f["fingerprint"] = fp_hex;
        ev.f["reason"] = reason;
        ev.f["http"] = std::to_string(http);
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);

        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    auto audit_ok = [&](const std::string& rel_path, std::uint64_t bytes) {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_zip_ok";
        ev.outcome = "ok";
        ev.f["fingerprint"] = fp_hex;
        ev.f["path"] = pqnas::shorten(rel_path, 200);
        ev.f["bytes"] = std::to_string((unsigned long long)bytes);

        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    // path param (directory)
    std::string rel_path;
    if (req.has_param("path")) rel_path = req.get_param_value("path");
    if (rel_path.empty()) {
        audit_fail("missing_path", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "missing path"}
        }.dump());
        return;
    }

    // Must be allocated (fail-closed)
    {
        auto uopt = users.get(fp_hex);
        if (!uopt.has_value()) {
            audit_fail("user_missing", 403);
            reply_json(res, 403, json{
                {"ok", false},
                {"error", "forbidden"},
                {"message", "policy denied"}
            }.dump());
            return;
        }
        const auto& u = *uopt;
        if (u.storage_state != "allocated") {
            audit_fail("storage_unallocated", 403);
            reply_json(res, 403, json{
                {"ok", false},
                {"error", "storage_unallocated"},
                {"message", "Storage not allocated"},
                {"fingerprint_hex", fp_hex},
                {"quota_bytes", u.quota_bytes}
            }.dump());
            return;
        }
    }

    // Resolve directory path strictly under user dir
    const std::filesystem::path user_dir = user_dir_for_fp(users, fp_hex);
    std::filesystem::path abs_dir;
    std::string perr;
    if (!pqnas::resolve_user_path_strict(user_dir, rel_path, &abs_dir, &perr)) {
        audit_fail("invalid_path", 400, perr);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid path"}
        }.dump());
        return;
    }

    // Refuse any symlink in the existing prefix chain
    {
        std::string serr;
        if (!ensure_no_symlink_in_existing_path_prefix(abs_dir, &serr)) {
            audit_fail("symlink_not_supported", 400, serr);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "symlinks not supported"},
                {"detail", serr}
            }.dump());
            return;
        }
    }

    // Validate exists + directory, without following symlinks
    std::error_code ec;
    auto st = std::filesystem::symlink_status(abs_dir, ec);
    if (ec || !std::filesystem::exists(st)) {
        audit_fail("not_found", 404);
        reply_json(res, 404, json{
            {"ok", false},
            {"error", "not_found"},
            {"message", "directory not found"}
        }.dump());
        return;
    }

    if (std::filesystem::is_symlink(st)) {
        audit_fail("symlink_not_supported", 400, abs_dir.string());
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "symlinks not supported"}
        }.dump());
        return;
    }

    if (!std::filesystem::is_directory(st)) {
        audit_fail("not_directory", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "not a directory"}
        }.dump());
        return;
    }

    // Collect files (pass 1)
    std::vector<ZipFileItem> items;
    std::uint64_t total_payload = 0;

    // ZIP will contain entries relative to rel_path root.
    // Example: rel_path="photos" => inside zip, paths like "photos/a.jpg" etc.
    // This makes it intuitive when extracted.
    const std::string zip_root = zip_sanitize_relpath(rel_path);
    const std::filesystem::path base = abs_dir;

    for (auto it = std::filesystem::recursive_directory_iterator(base, ec);
         !ec && it != std::filesystem::recursive_directory_iterator();
         it.increment(ec)) {

        if (ec) break;
        const auto& de = *it;

        std::error_code ec2;
        auto ent_st = std::filesystem::symlink_status(de.path(), ec2);
        if (ec2) {
            ec2.clear();
            continue;
        }

        // Never include symlinks in the zip, and never recurse through them.
        if (std::filesystem::is_symlink(ent_st)) {
            continue;
        }

        if (!std::filesystem::is_regular_file(ent_st)) {
            continue;
        }

        const std::filesystem::path abs = de.path();
        std::uint64_t sz = pqnas::file_size_u64_safe(abs);

        // build relative name within the selected directory
        std::filesystem::path rel_inside = std::filesystem::relative(abs, base, ec);
        if (ec) {
            ec.clear();
            continue;
        }

        std::string name = zip_root.empty()
            ? rel_inside.string()
            : (zip_root + "/" + rel_inside.string());

        name = zip_sanitize_relpath(name);
        if (name.empty()) continue;

        ZipFileItem z;
        z.abs_path = abs;
        z.zip_name = name;
        z.size_u64 = sz;

        std::uint16_t dt = 0, dd = 0;
        zip_dos_time_date(de.last_write_time(ec), dt, dd);
        if (ec) ec.clear();
        z.dos_time = dt;
        z.dos_date = dd;

        items.push_back(std::move(z));
        total_payload += sz;
    }

    if (ec) {
        audit_fail("iter_failed", 500, ec.message());
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "failed to enumerate directory"}
        }.dump());
        return;
    }

    if (items.empty()) {
        // Allow empty zips (valid), but still produce something useful.
        // We'll return a small zip with no entries.
    }

    // Sort stable by name for deterministic output
    std::sort(items.begin(), items.end(), [](const ZipFileItem& a, const ZipFileItem& b) {
        return a.zip_name < b.zip_name;
    });

    // Compute total zip size (exact, ZIP32)
    ZipTotals totals = zip_compute_totals(items);
    const std::uint64_t zip_bytes = totals.total_bytes;

    if (zip_bytes > 0xFFFFFFFFull) {
        audit_fail("zip_too_large_zip32", 413);
        reply_json(res, 413, json{
            {"ok", false},
            {"error", "too_large"},
            {"message", "directory too large for zip (zip32 limit)"}
        }.dump());
        return;
    }

    // Build filename
    std::string out_name = zip_basename(abs_dir) + ".zip";

    res.set_header("Cache-Control", "no-store");
    res.set_header("Content-Type", "application/zip");
    res.set_header("Content-Length", std::to_string((unsigned long long)zip_bytes));
    res.set_header("Content-Disposition", build_content_disposition("attachment", out_name));

    auto streamer = std::make_shared<ZipStreamer>(std::move(items), totals);

    res.set_content_provider(
        (size_t)zip_bytes,
        "application/zip",
        [streamer](size_t offset, size_t length, httplib::DataSink& sink) mutable {
            return streamer->emit(offset, length, sink);
        },
        [streamer](bool /*success*/) mutable {
            // nothing to close; files are opened/closed per entry inside streamer
        }
    );

    audit_ok(rel_path, zip_bytes);
});

// ---- Office document preview ------------------------------------------------
// Converts common Office/OpenDocument files to a temporary PDF using LibreOffice.
// These helpers are lambdas because this route block lives inside main().

auto lower_ext_no_dot_local = [](const std::filesystem::path& p) -> std::string {
    std::string e = p.extension().string();
    if (!e.empty() && e[0] == '.') e.erase(e.begin());
    for (char& c : e) c = static_cast<char>(std::tolower(static_cast<unsigned char>(c)));
    return e;
};

auto executable_in_path_local = [](const std::string& exe) -> bool {
    if (exe.empty()) return false;

    if (exe.find('/') != std::string::npos) {
        return ::access(exe.c_str(), X_OK) == 0;
    }

    const char* path_env = std::getenv("PATH");
    if (!path_env || !*path_env) return false;

    std::string path(path_env);
    std::size_t pos = 0;

    while (pos <= path.size()) {
        std::size_t next = path.find(':', pos);
        std::string dir = path.substr(pos, next == std::string::npos ? std::string::npos : next - pos);
        if (dir.empty()) dir = ".";

        const std::filesystem::path candidate = std::filesystem::path(dir) / exe;
        if (::access(candidate.c_str(), X_OK) == 0) return true;

        if (next == std::string::npos) break;
        pos = next + 1;
    }

    return false;
};

auto is_office_preview_ext_local = [](const std::string& ext) -> bool {
    static const std::set<std::string> kExts = {
        "doc", "docx",
        "xls", "xlsx",
        "ppt", "pptx",
        "odt", "ods", "odp",
        "rtf"
    };
    return kExts.find(ext) != kExts.end();
};

auto make_office_preview_tmpdir_local = [](std::string* err) -> std::filesystem::path {
    std::error_code ec;

    const auto base = std::filesystem::temp_directory_path(ec);
    if (ec) {
        if (err) *err = ec.message();
        return {};
    }

    for (int i = 0; i < 64; ++i) {
        const auto now = std::chrono::steady_clock::now().time_since_epoch().count();
        const auto p = base / (
            "pqnas-office-preview-" +
            std::to_string(static_cast<unsigned long long>(::getpid())) + "-" +
            std::to_string(static_cast<unsigned long long>(now)) + "-" +
            std::to_string(i)
        );

        std::filesystem::create_directory(p, ec);
        if (!ec) return p;
        ec.clear();
    }

    if (err) *err = "failed to create temporary directory";
    return {};
};

auto run_soffice_convert_pdf_local = [](const std::filesystem::path& in_file,
                                        const std::filesystem::path& out_dir,
                                        std::string* err) -> bool {
    pid_t pid = ::fork();
    if (pid < 0) {
        if (err) *err = "fork failed";
        return false;
    }

    if (pid == 0) {
        const std::string in_file_s = in_file.string();
        const std::string out_dir_s = out_dir.string();

        // LibreOffice may fail with exit code 77 when its default user profile
        // cannot be created/locked by the service user. Give each preview its own
        // temporary profile under the already-created preview temp directory.
        const std::string profile_arg =
            std::string("-env:UserInstallation=file://") + out_dir_s + "/lo-profile";

        ::setenv("HOME", out_dir_s.c_str(), 1);

        ::execlp(
            "soffice",
            "soffice",
            profile_arg.c_str(),
            "--headless",
            "--nologo",
            "--nofirststartwizard",
            "--convert-to",
            "pdf",
            "--outdir",
            out_dir_s.c_str(),
            in_file_s.c_str(),
            static_cast<char*>(nullptr)
        );

        _exit(127);
    }

    int status = 0;
    const auto deadline = std::chrono::steady_clock::now() + std::chrono::seconds(60);

    while (true) {
        pid_t r = ::waitpid(pid, &status, WNOHANG);
        if (r == pid) break;

        if (r < 0) {
            if (err) *err = "waitpid failed";
            return false;
        }

        if (std::chrono::steady_clock::now() > deadline) {
            ::kill(pid, SIGKILL);
            ::waitpid(pid, &status, 0);
            if (err) *err = "LibreOffice conversion timed out";
            return false;
        }

        std::this_thread::sleep_for(std::chrono::milliseconds(100));
    }

    if (!WIFEXITED(status) || WEXITSTATUS(status) != 0) {
        if (err) {
            *err = "LibreOffice conversion failed with exit code ";
            *err += WIFEXITED(status) ? std::to_string(WEXITSTATUS(status)) : "signal";
        }
        return false;
    }

    return true;
};

auto find_generated_pdf_local = [&](const std::filesystem::path& out_dir,
                                    std::string* err) -> std::filesystem::path {
    std::error_code ec;

    for (const auto& de : std::filesystem::directory_iterator(out_dir, ec)) {
        if (ec) break;
        if (!de.is_regular_file(ec)) {
            ec.clear();
            continue;
        }

        const auto ext = lower_ext_no_dot_local(de.path());
        if (ext == "pdf") return de.path();
    }

    if (err) *err = ec ? ec.message() : "LibreOffice did not produce a PDF";
    return {};
};

// GET /api/v4/files/office_preview?path=relative/document.docx
// Converts supported Office/OpenDocument files to PDF and streams the PDF inline.
srv.Get("/api/v4/files/office_preview", [&](const httplib::Request& req, httplib::Response& res) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;

    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto audit_fail = [&](const std::string& reason, int http, const std::string& detail = "") {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_office_preview_fail";
        ev.outcome = "fail";
        ev.f["fingerprint"] = fp_hex;
        ev.f["reason"] = reason;
        ev.f["http"] = std::to_string(http);
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    auto audit_ok = [&](const std::string& rel_path, std::uint64_t bytes) {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_office_preview_ok";
        ev.outcome = "ok";
        ev.f["fingerprint"] = fp_hex;
        ev.f["path"] = pqnas::shorten(rel_path, 200);
        ev.f["bytes"] = std::to_string((unsigned long long)bytes);
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    std::string rel_path;
    if (req.has_param("path")) rel_path = req.get_param_value("path");

    if (rel_path.empty()) {
        audit_fail("missing_path", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "missing path"}
        }.dump());
        return;
    }

    {
        auto uopt = users.get(fp_hex);
        if (!uopt.has_value()) {
            audit_fail("user_missing", 403);
            reply_json(res, 403, json{{"ok", false}, {"error", "forbidden"}, {"message", "policy denied"}}.dump());
            return;
        }

        const auto& u = *uopt;
        if (u.storage_state != "allocated") {
            audit_fail("storage_unallocated", 403);
            reply_json(res, 403, json{
                {"ok", false},
                {"error", "storage_unallocated"},
                {"message", "Storage not allocated"},
                {"fingerprint_hex", fp_hex},
                {"quota_bytes", u.quota_bytes}
            }.dump());
            return;
        }
    }

    pqnas::ResolvedExistingPath rp;
    std::string perr;
    if (!pqnas::resolve_existing_user_file_path(users, fp_hex, rel_path, &rp, &perr)) {
        audit_fail("invalid_path", 400, perr);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid path"}
        }.dump());
        return;
    }

    const std::filesystem::path abs = rp.abs_path;

    {
        std::string serr;
        if (!ensure_no_symlink_in_existing_path_prefix(abs, &serr)) {
            audit_fail("symlink_not_supported", 400, serr);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "symlinks not supported"}
            }.dump());
            return;
        }
    }

    std::error_code ec;
    auto st = std::filesystem::symlink_status(abs, ec);
    if (ec || !std::filesystem::exists(st)) {
        audit_fail("not_found", 404);
        reply_json(res, 404, json{
            {"ok", false},
            {"error", "not_found"},
            {"message", "file not found"}
        }.dump());
        return;
    }

    if (std::filesystem::is_symlink(st)) {
        audit_fail("symlink_not_supported", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "symlinks not supported"}
        }.dump());
        return;
    }

    if (!std::filesystem::is_regular_file(st)) {
        audit_fail("not_regular_file", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "not a regular file"}
        }.dump());
        return;
    }

    const std::string ext = lower_ext_no_dot_local(abs);
    if (!is_office_preview_ext_local(ext)) {
        audit_fail("unsupported_ext", 415, ext);
        reply_json(res, 415, json{
            {"ok", false},
            {"error", "unsupported_media_type"},
            {"message", "office preview supports doc/docx/xls/xlsx/ppt/pptx/odt/ods/odp/rtf"}
        }.dump());
        return;
    }

    const std::uint64_t input_sz = pqnas::file_size_u64_safe(abs);
    constexpr std::uint64_t kMaxOfficePreviewBytes = 50ull * 1024ull * 1024ull;
    if (input_sz > kMaxOfficePreviewBytes) {
        audit_fail("too_large", 413);
        reply_json(res, 413, json{
            {"ok", false},
            {"error", "too_large"},
            {"message", "office preview file is too large"}
        }.dump());
        return;
    }

    if (!executable_in_path_local("soffice")) {
        audit_fail("soffice_missing", 503);
        reply_json(res, 503, json{
            {"ok", false},
            {"error", "office_preview_unavailable"},
            {"message", "Office preview requires LibreOffice on this server"},
            {"detail", "soffice was not found in PATH"}
        }.dump());
        return;
    }

    std::string terr;
    const auto tmpdir = make_office_preview_tmpdir_local(&terr);
    if (tmpdir.empty()) {
        audit_fail("tmpdir_failed", 500, terr);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "failed to create temporary preview directory"}
        }.dump());
        return;
    }

    auto cleanup_tmpdir = std::make_shared<std::filesystem::path>(tmpdir);

    std::string cerr;
    if (!run_soffice_convert_pdf_local(abs, tmpdir, &cerr)) {
        std::error_code rm_ec;
        std::filesystem::remove_all(tmpdir, rm_ec);

        audit_fail("convert_failed", 500, cerr);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "conversion_failed"},
            {"message", "LibreOffice failed to convert this document"},
            {"detail", cerr}
        }.dump());
        return;
    }

    std::string ferr;
    const auto pdf_path = find_generated_pdf_local(tmpdir, &ferr);
    if (pdf_path.empty()) {
        std::error_code rm_ec;
        std::filesystem::remove_all(tmpdir, rm_ec);

        audit_fail("pdf_missing", 500, ferr);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "conversion_failed"},
            {"message", "converted PDF was not found"},
            {"detail", ferr}
        }.dump());
        return;
    }

    const std::uint64_t pdf_sz = pqnas::file_size_u64_safe(pdf_path);

    auto fp = std::make_shared<std::ifstream>(pdf_path, std::ios::binary);
    if (!fp->good()) {
        std::error_code rm_ec;
        std::filesystem::remove_all(tmpdir, rm_ec);

        audit_fail("open_pdf_failed", 500);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "failed to open converted PDF"}
        }.dump());
        return;
    }

    const std::string out_name = abs.stem().string() + ".pdf";

    res.set_header("Cache-Control", "no-store");
    res.set_header("Content-Disposition", build_content_disposition("inline", out_name));

    res.set_content_provider(
        static_cast<size_t>(pdf_sz),
        "application/pdf",
        [fp](size_t /*offset*/, size_t length, httplib::DataSink& sink) mutable {
            std::string buf;
            buf.resize(length);

            fp->read(buf.data(), static_cast<std::streamsize>(length));
            std::streamsize n = fp->gcount();
            if (n > 0) sink.write(buf.data(), static_cast<size_t>(n));

            return n > 0;
        },
        [fp, cleanup_tmpdir](bool /*success*/) mutable {
            if (fp && fp->is_open()) fp->close();

            std::error_code rm_ec;
            std::filesystem::remove_all(*cleanup_tmpdir, rm_ec);
        }
    );

    audit_ok(rel_path, pdf_sz);
});

// GET /api/v4/files/get?path=relative/path.bin
// Response: raw bytes (streams file)
srv.Get("/api/v4/files/get", [&](const httplib::Request& req, httplib::Response& res) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;

    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto audit_fail = [&](const std::string& reason, int http, const std::string& detail = "") {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_get_fail";
        ev.outcome = "fail";
        ev.f["fingerprint"] = fp_hex;
        ev.f["reason"] = reason;
        ev.f["http"] = std::to_string(http);
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);

        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    auto audit_ok = [&](const std::string& rel_path, std::uint64_t bytes) {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_get_ok";
        ev.outcome = "ok";
        ev.f["fingerprint"] = fp_hex;
        ev.f["path"] = pqnas::shorten(rel_path, 200);
        ev.f["bytes"] = std::to_string((unsigned long long)bytes);

        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    // path param
    std::string rel_path;
    if (req.has_param("path")) rel_path = req.get_param_value("path");
    if (rel_path.empty()) {
        audit_fail("missing_path", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "missing path"}
        }.dump());
        return;
    }

    // Must be allocated (fail-closed)
    {
        auto uopt = users.get(fp_hex);
        if (!uopt.has_value()) {
            audit_fail("user_missing", 403);
            reply_json(res, 403, json{{"ok", false}, {"error", "forbidden"}, {"message", "policy denied"}}.dump());
            return;
        }
        const auto& u = *uopt;
        if (u.storage_state != "allocated") {
            audit_fail("storage_unallocated", 403);
            reply_json(res, 403, json{
                {"ok", false},
                {"error", "storage_unallocated"},
                {"message", "Storage not allocated"},
                {"fingerprint_hex", fp_hex},
                {"quota_bytes", u.quota_bytes}
            }.dump());
            return;
        }
    }

    // Resolve file path strictly under user dir
    pqnas::ResolvedExistingPath rp;
    std::string perr;
    if (!pqnas::resolve_existing_user_file_path(users, fp_hex, rel_path, &rp, &perr)) {
        audit_fail("invalid_path", 400, perr);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid path"}
        }.dump());
        return;
    }

    const std::filesystem::path abs = rp.abs_path;

    {
    std::string serr;
    if (!ensure_no_symlink_in_existing_path_prefix(abs, &serr)) {
        audit_fail("symlink_not_supported", 400, serr);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "symlinks not supported"}
        }.dump());
        return;
    }
}

    // Validate exists + regular + size
    std::error_code ec;
    auto st = std::filesystem::symlink_status(abs, ec);
    if (ec || !std::filesystem::exists(st)) {
        audit_fail("not_found", 404);
        reply_json(res, 404, json{
            {"ok", false},
            {"error", "not_found"},
            {"message", "file not found"}
        }.dump());
        return;
    }
    if (std::filesystem::is_symlink(st)) {
        audit_fail("symlink_not_supported", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "symlinks not supported"}
        }.dump());
        return;
    }
    if (!std::filesystem::is_regular_file(st)) {
        audit_fail("not_regular_file", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "not a regular file"}
        }.dump());
        return;
    }

    const std::uint64_t sz = pqnas::file_size_u64_safe(abs);

    // Stream it
    auto fp = std::make_shared<std::ifstream>(abs, std::ios::binary);
    if (!fp->good()) {
        audit_fail("open_failed", 500);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "failed to open file"}
        }.dump());
        return;
    }

    const std::string mime = guess_download_mime_from_name(abs.filename().string());
    const bool inline_preview = is_inline_preview_mime(mime);

    res.set_header("Cache-Control", "no-store");

    res.set_header(
        "Content-Disposition",
        build_content_disposition(
            inline_preview ? "inline" : "attachment",
            abs.filename().string()
        )
    );

    res.set_header("Accept-Ranges", "bytes");

    // httplib calls this provider with the exact byte offset requested by
    // normal downloads, single Range requests, and multi-range media probes.
    // We must seek to that offset every time; otherwise Range headers are
    // correct but the body comes from the wrong place.
    res.set_content_provider(
        static_cast<size_t>(sz),
        mime.c_str(),
        [fp](size_t offset, size_t length, httplib::DataSink& sink) mutable {
            if (!fp || !fp->is_open()) return false;

            fp->clear();
            fp->seekg(static_cast<std::streamoff>(offset), std::ios::beg);
            if (!fp->good()) return false;

            constexpr size_t kChunk = 64 * 1024;
            std::vector<char> buf;
            buf.resize(std::min(kChunk, length));

            size_t remaining = length;

            while (remaining > 0) {
                const size_t want = std::min(buf.size(), remaining);

                fp->read(buf.data(), static_cast<std::streamsize>(want));
                const std::streamsize got = fp->gcount();

                if (got <= 0) break;

                sink.write(buf.data(), static_cast<size_t>(got));
                remaining -= static_cast<size_t>(got);

                if (static_cast<size_t>(got) < want) break;
            }

            return remaining == 0;
        },
        [fp](bool /*success*/) mutable {
            if (fp && fp->is_open()) fp->close();
        }
    );


    audit_ok(rel_path, sz);
});

// GET /api/v4/gallery/list?path=relative/dir
// Lists immediate children for Photo Gallery:
// - directories are always included
// - files are included only if they look like supported images
// - joins gallery metadata for exact child files and returns both old and standardized fields
srv.Get("/api/v4/gallery/list", [&](const httplib::Request& req, httplib::Response& res) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;

    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto add_ip_headers = [&](pqnas::AuditEvent& ev) {
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
    };

    auto audit_fail = [&](const std::string& reason, int http,
                          const std::string& detail = "",
                          const std::string& rel_dir = "") {
        pqnas::AuditEvent ev;
        ev.event = "v4.gallery_list_fail";
        ev.outcome = "fail";
        ev.f["fingerprint"] = fp_hex;
        ev.f["reason"] = reason;
        ev.f["http"] = std::to_string(http);
        if (!rel_dir.empty()) ev.f["path"] = pqnas::shorten(rel_dir, 200);
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);
        add_ip_headers(ev);
        audit_append(ev);
    };

    auto audit_ok = [&](const std::string& rel_dir, std::size_t count) {
        pqnas::AuditEvent ev;
        ev.event = "v4.gallery_list_ok";
        ev.outcome = "ok";
        ev.f["fingerprint"] = fp_hex;
        ev.f["path"] = pqnas::shorten(rel_dir, 200);
        ev.f["count"] = std::to_string((unsigned long long)count);
        add_ip_headers(ev);
        audit_append(ev);
    };

    auto lower_ascii_local = [](std::string s) -> std::string {
        for (char& c : s) c = (char)std::tolower((unsigned char)c);
        return s;
    };

    auto is_reserved_name = [&](const std::string& name) -> bool {
        return name == ".pqnas";
    };

    auto file_ext_lower = [&](const std::string& name) -> std::string {
        std::string n = name;
        const auto slash = n.find_last_of("/\\");
        if (slash != std::string::npos) n = n.substr(slash + 1);

        auto lower = lower_ascii_local(n);
        const auto dot = lower.rfind('.');
        if (dot == std::string::npos || dot == 0 || dot + 1 >= lower.size()) return "";
        return lower.substr(dot + 1);
    };

    auto is_gallery_image_name = [&](const std::string& name) -> bool {
        const std::string ext = file_ext_lower(name);
        return ext == "png"  ||
               ext == "jpg"  ||
               ext == "jpeg" ||
               ext == "gif"  ||
               ext == "webp" ||
               ext == "svg"  ||
               ext == "bmp"  ||
               ext == "ico"  ||
               ext == "tif"  ||
               ext == "tiff" ||
               ext == "heic" ||
               ext == "heif" ||
               ext == "cr2"  ||
               ext == "cr3"  ||
               ext == "nef"  ||
               ext == "arw"  ||
               ext == "raf"  ||
               ext == "dng"  ||
               ext == "rw2"  ||
               ext == "orf";
    };
    auto join_rel = [&](const std::string& base, const std::string& name) -> std::string {
        if (base.empty()) return name;
        return base + "/" + name;
    };
    auto split_gallery_keywords_text_json = [](const std::string& s) -> json {
    auto trim_ascii_ws_copy_local = [](std::string v) -> std::string {
        auto is_ws = [](unsigned char c) -> bool {
            return c == ' ' || c == '\t' || c == '\r' || c == '\n';
        };

        std::size_t a = 0;
        while (a < v.size() && is_ws((unsigned char)v[a])) ++a;

        std::size_t b = v.size();
        while (b > a && is_ws((unsigned char)v[b - 1])) --b;

        return v.substr(a, b - a);
    };

    json out = json::array();

    std::size_t start = 0;
    while (start <= s.size()) {
        const std::size_t comma = s.find(',', start);

        std::string part = (comma == std::string::npos)
            ? s.substr(start)
            : s.substr(start, comma - start);

        part = trim_ascii_ws_copy_local(part);
        if (!part.empty()) out.push_back(part);

        if (comma == std::string::npos) break;
        start = comma + 1;
    }

    return out;
};
    // Storage allocated check (fail-closed)
    {
        auto uopt = users.get(fp_hex);
        if (!uopt.has_value()) {
            audit_fail("user_missing", 403);
            reply_json(res, 403, json{
                {"ok", false},
                {"error", "forbidden"},
                {"message", "policy denied"}
            }.dump());
            return;
        }

        const auto& u = *uopt;
        if (u.storage_state != "allocated") {
            audit_fail("storage_unallocated", 403);
            reply_json(res, 403, json{
                {"ok", false},
                {"error", "storage_unallocated"},
                {"message", "Storage not allocated"},
                {"fingerprint_hex", fp_hex},
                {"quota_bytes", u.quota_bytes}
            }.dump());
            return;
        }
    }

    std::string rel_dir;
    if (req.has_param("path")) rel_dir = req.get_param_value("path");

    const std::filesystem::path user_dir = user_dir_for_fp(users, fp_hex);
    std::filesystem::path abs_dir = user_dir;
    std::string rel_dir_norm;

    if (!rel_dir.empty()) {
        std::string nerr;
        if (!pqnas::normalize_user_rel_path_strict(rel_dir, &rel_dir_norm, &nerr)) {
            audit_fail("invalid_path", 400, nerr, rel_dir);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "invalid path"}
            }.dump());
            return;
        }

        std::string perr;
        if (!pqnas::resolve_user_path_strict(user_dir, rel_dir_norm, &abs_dir, &perr)) {
            // Do not fail yet: dir may exist only logically via metadata.
            abs_dir.clear();
        }
    }

    struct ListedItem {
        std::string name;
        std::string type; // "dir" | "file"
        std::uint64_t size_bytes = 0;
        long long mtime_unix = 0;

        int rating = 0;
        std::string tags_text;
        std::string notes_text;

        std::string capture_time_text;
        std::int64_t capture_time_unix = 0;

        double gps_latitude = 0.0;
        double gps_longitude = 0.0;
        double gps_altitude = 0.0;
        bool has_gps = false;
        bool has_gps_altitude = false;
    };

    std::map<std::string, ListedItem> merged;

    // 1) Legacy physical immediate children, if physical dir exists.
    bool legacy_dir_ok = false;
    {
        std::error_code ec;
        std::filesystem::path dir_to_check = abs_dir.empty() ? user_dir : abs_dir;
        auto st = std::filesystem::symlink_status(dir_to_check, ec);

        if (!ec && std::filesystem::exists(st)) {
            if (std::filesystem::is_symlink(st)) {
                audit_fail("symlink_not_supported", 400, "", rel_dir_norm.empty() ? rel_dir : rel_dir_norm);
                reply_json(res, 400, json{
                    {"ok", false},
                    {"error", "bad_request"},
                    {"message", "symlinks not supported"}
                }.dump());
                return;
            }

            if (std::filesystem::is_directory(st)) {
                legacy_dir_ok = true;

                for (std::filesystem::directory_iterator it(dir_to_check, ec), end; it != end && !ec; it.increment(ec)) {
                    std::error_code ec2;
                    const auto child_path = it->path();
                    const auto name = child_path.filename().string();

                    if (name.empty() || name == "." || name == "..") continue;
                    if (is_reserved_name(name)) continue;

                    auto child_st = std::filesystem::symlink_status(child_path, ec2);
                    if (ec2) continue;
                    if (std::filesystem::is_symlink(child_st)) continue;

                    if (std::filesystem::is_directory(child_st)) {
                        long long mtime_unix = 0;
                        ec2.clear();
                        auto ft = std::filesystem::last_write_time(child_path, ec2);
                        if (!ec2) {
                            using namespace std::chrono;
                            auto sctp = time_point_cast<system_clock::duration>(
                                ft - decltype(ft)::clock::now() + system_clock::now()
                            );
                            mtime_unix = (long long)duration_cast<seconds>(sctp.time_since_epoch()).count();
                        }

                        merged[name] = ListedItem{
                            name, "dir", 0, mtime_unix, 0, "", "", "", 0, 0.0, 0.0, 0.0, false, false
                        };
                        continue;
                    }

                    if (std::filesystem::is_regular_file(child_st) && is_gallery_image_name(name)) {
                        std::uint64_t size_bytes = 0;
                        ec2.clear();
                        auto sz = std::filesystem::file_size(child_path, ec2);
                        if (!ec2) size_bytes = static_cast<std::uint64_t>(sz);

                        long long mtime_unix = 0;
                        ec2.clear();
                        auto ft = std::filesystem::last_write_time(child_path, ec2);
                        if (!ec2) {
                            using namespace std::chrono;
                            auto sctp = time_point_cast<system_clock::duration>(
                                ft - decltype(ft)::clock::now() + system_clock::now()
                            );
                            mtime_unix = (long long)duration_cast<seconds>(sctp.time_since_epoch()).count();
                        }

                        merged[name] = ListedItem{
                            name, "file", size_bytes, mtime_unix, 0, "", "", "", 0, 0.0, 0.0, 0.0, false, false
                        };
                    }
                }
            }
        }
    }

    // 2) Merge metadata-backed immediate children from file_locations.
    bool metadata_ok = false;
    {
        auto* idx = pqnas::get_file_location_index();
        if (!idx) {
            audit_fail("metadata_index_missing", 500, "", rel_dir_norm.empty() ? rel_dir : rel_dir_norm);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "metadata index missing"}
            }.dump());
            return;
        }

        std::string lerr;
        auto rows = idx->list_immediate_children(fp_hex, rel_dir_norm, &lerr);
        if (!lerr.empty()) {
            audit_fail("metadata_list_failed", 500, lerr, rel_dir_norm.empty() ? rel_dir : rel_dir_norm);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "metadata list failed"},
                {"detail", pqnas::shorten(lerr, 180)}
            }.dump());
            return;
        }

        if (!rows.empty()) metadata_ok = true;

        for (const auto& rec : rows) {
            if (rec.name.empty()) continue;
            if (is_reserved_name(rec.name)) continue;

            const std::string t = rec.type.empty() ? "file" : rec.type;
            if (t != "dir" && t != "file") continue;
            if (t == "file" && !is_gallery_image_name(rec.name)) continue;

            auto it = merged.find(rec.name);
            if (it == merged.end()) {
                merged[rec.name] = ListedItem{
                    rec.name,
                    t,
                    (t == "file" ? rec.size_bytes : 0),
                    (long long)rec.mtime_epoch,
                    0,
                    "",
                    "",
                    "",
                    0,
                    0.0,
                    0.0,
                    0.0,
                    false,
                    false
                };
            } else {
                it->second.type = t;
                it->second.size_bytes = (t == "file" ? rec.size_bytes : 0);
                it->second.mtime_unix = (long long)rec.mtime_epoch;
            }
        }
    }

    if (!legacy_dir_ok && !metadata_ok && !rel_dir_norm.empty()) {
        audit_fail("not_found", 404, "", rel_dir_norm);
        reply_json(res, 404, json{
            {"ok", false},
            {"error", "not_found"},
            {"message", "directory not found"}
        }.dump());
        return;
    }

    // 3) Join gallery metadata for exact child files.
    {
        auto* gidx = pqnas::get_gallery_meta_index();
        if (!gidx) {
            audit_fail("gallery_meta_index_missing", 500, "", rel_dir_norm.empty() ? rel_dir : rel_dir_norm);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "gallery metadata index missing"}
            }.dump());
            return;
        }

        for (auto& kv : merged) {
            auto& item = kv.second;
            if (item.type != "file") continue;

            const std::string child_rel = join_rel(rel_dir_norm, item.name);

            std::string gerr;
            auto grec = gidx->get("user", fp_hex, child_rel, &gerr);
            if (!gerr.empty()) {
                audit_fail("gallery_meta_lookup_failed", 500, gerr, child_rel);
                reply_json(res, 500, json{
                    {"ok", false},
                    {"error", "server_error"},
                    {"message", "gallery metadata lookup failed"},
                    {"detail", pqnas::shorten(gerr, 180)}
                }.dump());
                return;
            }

            if (grec.has_value()) {
                item.rating = grec->rating;
                item.tags_text = grec->tags_text;
                item.notes_text = grec->notes_text;

                // Prefer fresher gallery-cached facts only if file_locations did not provide them.
                if (grec.has_value()) {
                    item.rating = grec->rating;
                    item.tags_text = grec->tags_text;
                    item.notes_text = grec->notes_text;

                    if (grec->size_bytes > 0) {
                        item.size_bytes = grec->size_bytes;
                    }
                    if (grec->mtime_epoch > 0) {
                        item.mtime_unix = (long long)grec->mtime_epoch;
                    }
                }
            }
        }
    }
    // 4) Best-effort EXIF capture-time cache for visible image files.
    sqlite3* photo_db = nullptr;
    {
        const std::filesystem::path photo_db_path =
            std::filesystem::path(pqnas::data_root_dir()) / "photogallery_stats.sqlite3";

        if (sqlite3_open(photo_db_path.string().c_str(), &photo_db) != SQLITE_OK) {
            if (photo_db) {
                sqlite3_close(photo_db);
                photo_db = nullptr;
            }
        } else {
            std::string schema_err;
            if (!ensure_photo_stats_schema(photo_db, &schema_err)) {
                sqlite3_close(photo_db);
                photo_db = nullptr;
            }
        }
    }

    if (photo_db) {
        for (auto& kv : merged) {
            auto& item = kv.second;
            if (item.type != "file") continue;

            const std::string child_rel = join_rel(rel_dir_norm, item.name);

            PhotoStatsRow row;
            bool have_row = load_cached_photo_stats_row(photo_db, child_rel, &row);

            const bool cache_match =
                have_row &&
                row.size_bytes == item.size_bytes &&
                row.mtime_epoch == static_cast<std::int64_t>(item.mtime_unix);

            if (!cache_match) {
                pqnas::ResolvedLogicalItem resolved;
                std::string rerr;

                if (pqnas::resolve_existing_user_item(users, fp_hex, child_rel, &resolved, &rerr) &&
                    resolved.exists &&
                    resolved.is_file &&
                    resolved.has_physical_anchor) {

                    std::uint64_t exif_size = item.size_bytes;
                    std::int64_t exif_mtime = static_cast<std::int64_t>(item.mtime_unix);

                    if (exif_size == 0) {
                        exif_size = file_size_u64_safe_local(resolved.abs_path);
                        item.size_bytes = exif_size;
                    }

                    if (exif_mtime == 0) {
                        exif_mtime = file_mtime_epoch_safe_local(resolved.abs_path);
                        item.mtime_unix = static_cast<long long>(exif_mtime);
                    }

                    PhotoStatsRow fresh;
                    std::string ferr;
                    if (refresh_one_photo_exif_row(photo_db,
                                                   child_rel,
                                                   resolved.abs_path,
                                                   exif_size,
                                                   exif_mtime,
                                                   &fresh,
                                                   &ferr)) {
                        row = std::move(fresh);
                        have_row = true;
                    }
                }
            }

            if (have_row) {
                item.capture_time_text = row.taken_at;
                item.capture_time_unix = row.taken_epoch;
                if (row.gps_ok) {
                    item.gps_latitude = row.gps_latitude;
                    item.gps_longitude = row.gps_longitude;
                    item.gps_altitude = row.gps_altitude;
                    item.has_gps = true;
                    item.has_gps_altitude = row.gps_altitude_ok;
                }
            }
        }

        sqlite3_close(photo_db);
        photo_db = nullptr;
    }
    json out;
    out["ok"] = true;
    out["fingerprint_hex"] = fp_hex;
    out["path"] = rel_dir_norm.empty() ? rel_dir : rel_dir_norm;
    out["items"] = json::array();

    std::size_t count = 0;
    for (const auto& kv : merged) {
        const auto& item = kv.second;
        out["items"].push_back(json{
            {"name", item.name},
            {"type", item.type},
            {"size_bytes", item.size_bytes},
            {"mtime_unix", item.mtime_unix},
            {"capture_time_text", item.capture_time_text},
            {"capture_time_unix", item.capture_time_unix},
            {"has_gps", item.has_gps},
            {"gps_latitude", item.has_gps ? json(item.gps_latitude) : json(nullptr)},
            {"gps_longitude", item.has_gps ? json(item.gps_longitude) : json(nullptr)},
            {"gps_altitude", (item.has_gps && item.has_gps_altitude) ? json(item.gps_altitude) : json(nullptr)},

            // New standardized fields
            {"imageRating", item.rating},
            {"keywords", split_gallery_keywords_text_json(item.tags_text)},
            {"description", json{
                {"x-default", item.notes_text}
            }},

            // Old compatibility fields
            {"rating", item.rating},
            {"tags_text", item.tags_text},
            {"notes_text", item.notes_text}
        });
        count++;
        if (count >= 5000) break;
    }

    const std::string out_path = rel_dir_norm.empty() ? rel_dir : rel_dir_norm;
    audit_ok(out_path, count);
    reply_json(res, 200, out.dump());
});

// GET /api/v4/music/cover?path=relative/audio/file.mp3
// Returns embedded album art if present. 404 = no embedded cover, so clients can fallback to folder.jpg/cover.jpg.
srv.Get("/api/v4/music/cover", [&](const httplib::Request& req, httplib::Response& res) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;

    auto reply = [&](int status, const json& j) {
        res.status = status;
        res.set_header("Cache-Control", "no-store");
        res.set_content(j.dump(2), "application/json; charset=utf-8");
    };

    auto lower_ascii = [&](std::string s) -> std::string {
        for (char& c : s) c = static_cast<char>(std::tolower(static_cast<unsigned char>(c)));
        return s;
    };

    auto is_supported_audio_ext = [&](const std::string& name) -> bool {
        const std::string n = lower_ascii(name);
        const auto dot = n.rfind('.');
        if (dot == std::string::npos) return false;
        const std::string ext = n.substr(dot + 1);

        return ext == "mp3"  || ext == "flac" || ext == "m4a" ||
               ext == "aac"  || ext == "ogg"  || ext == "oga"  ||
               ext == "opus" || ext == "wav"  || ext == "aif"  ||
               ext == "aiff" || ext == "alac" || ext == "wma";
    };

    auto image_mime_from_bytes = [&](const std::string& buf) -> std::string {
        if (buf.size() >= 3 &&
            static_cast<unsigned char>(buf[0]) == 0xff &&
            static_cast<unsigned char>(buf[1]) == 0xd8 &&
            static_cast<unsigned char>(buf[2]) == 0xff) {
            return "image/jpeg";
        }

        if (buf.size() >= 8 &&
            static_cast<unsigned char>(buf[0]) == 0x89 &&
            buf[1] == 'P' && buf[2] == 'N' && buf[3] == 'G' &&
            static_cast<unsigned char>(buf[4]) == 0x0d &&
            static_cast<unsigned char>(buf[5]) == 0x0a &&
            static_cast<unsigned char>(buf[6]) == 0x1a &&
            static_cast<unsigned char>(buf[7]) == 0x0a) {
            return "image/png";
        }

        if (buf.size() >= 12 &&
            buf.compare(0, 4, "RIFF") == 0 &&
            buf.compare(8, 4, "WEBP") == 0) {
            return "image/webp";
        }

        return "";
    };

    auto file_mtime_epoch = [&](const std::filesystem::path& p) -> std::int64_t {
        std::error_code ec;
        auto ft = std::filesystem::last_write_time(p, ec);
        if (ec) return 0;

        using namespace std::chrono;
        auto sctp = time_point_cast<system_clock::duration>(
            ft - std::filesystem::file_time_type::clock::now() + system_clock::now()
        );
        return static_cast<std::int64_t>(duration_cast<seconds>(sctp.time_since_epoch()).count());
    };

    auto fnv1a64 = [&](const std::string& s) -> std::uint64_t {
        std::uint64_t h = 1469598103934665603ULL;
        for (unsigned char c : s) {
            h ^= static_cast<std::uint64_t>(c);
            h *= 1099511628211ULL;
        }
        return h;
    };

    auto hex_u64 = [&](std::uint64_t v) -> std::string {
        std::ostringstream oss;
        oss << std::hex << std::nouppercase << v;
        return oss.str();
    };

    auto read_small_file = [&](const std::filesystem::path& p, std::string* out, std::string* err) -> bool {
        if (out) out->clear();
        if (err) err->clear();

        std::ifstream f(p, std::ios::binary);
        if (!f.good()) {
            if (err) *err = "open failed";
            return false;
        }

        std::ostringstream oss;
        oss << f.rdbuf();

        if (!f.good() && !f.eof()) {
            if (err) *err = "read failed";
            return false;
        }

        if (out) *out = oss.str();
        return true;
    };

    auto spawn_stdout_to_file = [&](const std::vector<std::string>& args,
                                    const std::filesystem::path& out_path) -> int {
        if (args.empty()) return 127;

        std::vector<char*> argv;
        argv.reserve(args.size() + 1);
        for (const auto& s : args) argv.push_back(const_cast<char*>(s.c_str()));
        argv.push_back(nullptr);

        pid_t pid = fork();
        if (pid < 0) return 127;

        if (pid == 0) {
            int out_fd = open(out_path.c_str(), O_CREAT | O_TRUNC | O_WRONLY, 0600);
            if (out_fd < 0) _exit(127);

            dup2(out_fd, STDOUT_FILENO);
            close(out_fd);

            int devnull = open("/dev/null", O_WRONLY);
            if (devnull >= 0) {
                dup2(devnull, STDERR_FILENO);
                close(devnull);
            }

            execvp(argv[0], argv.data());
            _exit(127);
        }

        int st = 0;
        while (waitpid(pid, &st, 0) < 0) {
            if (errno == EINTR) continue;
            return 127;
        }

        if (WIFEXITED(st)) return WEXITSTATUS(st);
        if (WIFSIGNALED(st)) return 128 + WTERMSIG(st);
        return 127;
    };

    auto cache_root = [&]() -> std::filesystem::path {
        return std::filesystem::path(pqnas::data_root_dir()).parent_path() / "cache" / "music_covers";
    };

    {
        auto uopt = users.get(fp_hex);
        if (!uopt.has_value() || uopt->storage_state != "allocated") {
            reply(403, {
                {"ok", false},
                {"error", "storage_unallocated"},
                {"message", "Storage not allocated"}
            });
            return;
        }
    }

    std::string rel_path;
    if (req.has_param("path")) rel_path = req.get_param_value("path");
    if (rel_path.empty()) {
        reply(400, {
            {"ok", false},
            {"error", "bad_request"},
            {"message", "missing path"}
        });
        return;
    }

    std::string rel_norm;
    {
        std::string nerr;
        if (!pqnas::normalize_user_rel_path_strict(rel_path, &rel_norm, &nerr)) {
            reply(400, {
                {"ok", false},
                {"error", "bad_request"},
                {"message", "invalid path"}
            });
            return;
        }
    }

    pqnas::ResolvedExistingPath rp;
    std::string perr;
    if (!pqnas::resolve_existing_user_file_path(users, fp_hex, rel_path, &rp, &perr)) {
        reply(400, {
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid path"}
        });
        return;
    }

    const std::filesystem::path abs = rp.abs_path;

    {
        std::string serr;
        if (!ensure_no_symlink_in_existing_path_prefix(abs, &serr)) {
            reply(400, {
                {"ok", false},
                {"error", "bad_request"},
                {"message", "symlinks not supported"}
            });
            return;
        }
    }

    std::error_code ec;
    auto st = std::filesystem::symlink_status(abs, ec);
    if (ec || !std::filesystem::exists(st)) {
        reply(404, {
            {"ok", false},
            {"error", "not_found"},
            {"message", "file not found"}
        });
        return;
    }

    if (std::filesystem::is_symlink(st)) {
        reply(400, {
            {"ok", false},
            {"error", "bad_request"},
            {"message", "symlinks not supported"}
        });
        return;
    }

    if (!std::filesystem::is_regular_file(st)) {
        reply(400, {
            {"ok", false},
            {"error", "bad_request"},
            {"message", "not a regular file"}
        });
        return;
    }

    if (!is_supported_audio_ext(abs.filename().string())) {
        reply(415, {
            {"ok", false},
            {"error", "unsupported_media_type"},
            {"message", "unsupported audio type"}
        });
        return;
    }

    const std::uint64_t src_bytes = pqnas::file_size_u64_safe(abs);
    const std::int64_t src_mtime = file_mtime_epoch(abs);

    const std::string key_material =
        fp_hex + "\n" +
        rel_norm + "\n" +
        std::to_string((unsigned long long)src_bytes) + "\n" +
        std::to_string((long long)src_mtime);

    const std::string cover_key = hex_u64(fnv1a64(key_material));

    const std::filesystem::path cache_dir = cache_root() / fp_hex;
    const std::filesystem::path cache_abs = cache_dir / (cover_key + ".bin");

    auto serve_cover = [&](bool cached) {
        std::string buf;
        std::string rerr;
        if (!read_small_file(cache_abs, &buf, &rerr)) {
            reply(500, {
                {"ok", false},
                {"error", "server_error"},
                {"message", "failed to read cached cover"}
            });
            return;
        }

        const std::string mime = image_mime_from_bytes(buf);
        if (mime.empty()) {
            std::error_code rm_ec;
            std::filesystem::remove(cache_abs, rm_ec);

            reply(404, {
                {"ok", false},
                {"error", "not_found"},
                {"message", "no embedded cover art"}
            });
            return;
        }

        res.status = 200;
        res.set_header("Cache-Control", cached ? "private, max-age=86400" : "private, max-age=3600");
        res.set_header("X-Content-Type-Options", "nosniff");
        res.set_content(std::move(buf), mime);
    };

    {
        std::error_code cec;
        auto cst = std::filesystem::symlink_status(cache_abs, cec);
        if (!cec &&
            std::filesystem::exists(cst) &&
            !std::filesystem::is_symlink(cst) &&
            std::filesystem::is_regular_file(cst)) {
            serve_cover(true);
            return;
        }
    }

    ec.clear();
    std::filesystem::create_directories(cache_dir, ec);
    if (ec) {
        reply(500, {
            {"ok", false},
            {"error", "server_error"},
            {"message", "failed to create cover cache directory"}
        });
        return;
    }

    const std::filesystem::path tmp_abs =
        cache_dir / (cover_key + ".tmp." + random_b64url(8) + ".bin");

    const std::vector<std::string> exes = {
        "/usr/bin/exiftool",
        "/usr/local/bin/exiftool",
        "exiftool"
    };

    const std::vector<std::string> tags = {
        "Picture",
        "CoverArt",
        "FrontCover",
        "AlbumArt"
    };

    bool extracted = false;

    for (const auto& exe : exes) {
        for (const auto& tag : tags) {
            std::error_code rm_ec;
            std::filesystem::remove(tmp_abs, rm_ec);

            const std::vector<std::string> args = {
                exe,
                "-b",
                "-" + tag,
                abs.string()
            };

            const int rc = spawn_stdout_to_file(args, tmp_abs);
            if (rc != 0) continue;

            std::string test;
            std::string rerr;
            if (!read_small_file(tmp_abs, &test, &rerr)) continue;

            if (test.empty()) continue;
            if (test.size() > 20ULL * 1024ULL * 1024ULL) continue;
            if (image_mime_from_bytes(test).empty()) continue;

            extracted = true;
            break;
        }

        if (extracted) break;
    }

    if (!extracted) {
        std::error_code rm_ec;
        std::filesystem::remove(tmp_abs, rm_ec);

        reply(404, {
            {"ok", false},
            {"error", "not_found"},
            {"message", "no embedded cover art"}
        });
        return;
    }

    {
        std::error_code ren_ec;
        std::filesystem::rename(tmp_abs, cache_abs, ren_ec);
        if (ren_ec) {
            std::error_code cec;
            auto cst = std::filesystem::symlink_status(cache_abs, cec);

            if (!cec &&
                std::filesystem::exists(cst) &&
                !std::filesystem::is_symlink(cst) &&
                std::filesystem::is_regular_file(cst)) {
                std::error_code rm_ec;
                std::filesystem::remove(tmp_abs, rm_ec);
            } else {
                std::error_code rm_ec;
                std::filesystem::remove(tmp_abs, rm_ec);

                reply(500, {
                    {"ok", false},
                    {"error", "server_error"},
                    {"message", "failed to finalize cover cache"}
                });
                return;
            }
        }
    }

    serve_cover(false);
});

srv.Get("/api/v4/gallery/thumb", [&](const httplib::Request& req, httplib::Response& res) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;

    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto audit_fail = [&](const std::string& reason, int http, const std::string& detail = "") {
        pqnas::AuditEvent ev;
        ev.event = "v4.gallery_thumb_fail";
        ev.outcome = "fail";
        ev.f["fingerprint"] = fp_hex;
        ev.f["reason"] = reason;
        ev.f["http"] = std::to_string(http);
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    auto audit_ok = [&](const std::string& rel_path_norm, bool cached, std::uint64_t bytes) {
        pqnas::AuditEvent ev;
        ev.event = "v4.gallery_thumb_ok";
        ev.outcome = "ok";
        ev.f["fingerprint"] = fp_hex;
        ev.f["path"] = pqnas::shorten(rel_path_norm, 200);
        ev.f["cached"] = cached ? "1" : "0";
        ev.f["bytes"] = std::to_string((unsigned long long)bytes);
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    auto fnv1a64 = [&](const std::string& s) -> std::uint64_t {
        std::uint64_t h = 1469598103934665603ULL;
        for (unsigned char c : s) {
            h ^= static_cast<std::uint64_t>(c);
            h *= 1099511628211ULL;
        }
        return h;
    };

    auto hex_u64 = [&](std::uint64_t v) -> std::string {
        std::ostringstream oss;
        oss << std::hex << std::nouppercase << v;
        return oss.str();
    };

    auto lower_ascii = [&](std::string s) -> std::string {
        for (char& c : s) c = static_cast<char>(std::tolower(static_cast<unsigned char>(c)));
        return s;
    };

    auto is_supported_gallery_thumb_ext = [&](const std::string& name) -> bool {
        const std::string n = lower_ascii(name);
        const auto dot = n.rfind('.');
        if (dot == std::string::npos) return false;
        const std::string ext = n.substr(dot + 1);

        return ext == "jpg"  || ext == "jpeg" ||
               ext == "png"  || ext == "webp" ||
               ext == "bmp"  || ext == "gif"  ||
               ext == "tif"  || ext == "tiff" ||
               ext == "heic" || ext == "heif";
    };

    auto file_mtime_epoch = [&](const std::filesystem::path& p) -> std::int64_t {
        std::error_code ec;
        auto ft = std::filesystem::last_write_time(p, ec);
        if (ec) return 0;

        using namespace std::chrono;
        auto sctp = time_point_cast<system_clock::duration>(
            ft - std::filesystem::file_time_type::clock::now() + system_clock::now()
        );
        return static_cast<std::int64_t>(duration_cast<seconds>(sctp.time_since_epoch()).count());
    };

    auto read_small_file = [&](const std::filesystem::path& p, std::string* out, std::string* err) -> bool {
        if (out) out->clear();
        if (err) err->clear();

        std::ifstream f(p, std::ios::binary);
        if (!f.good()) {
            if (err) *err = "open failed";
            return false;
        }

        std::ostringstream oss;
        oss << f.rdbuf();

        if (!f.good() && !f.eof()) {
            if (err) *err = "read failed";
            return false;
        }

        if (out) *out = oss.str();
        return true;
    };

    auto spawn_wait = [&](const std::vector<std::string>& args) -> int {
        if (args.empty()) return 127;

        std::vector<char*> argv;
        argv.reserve(args.size() + 1);
        for (const auto& s : args) argv.push_back(const_cast<char*>(s.c_str()));
        argv.push_back(nullptr);

        pid_t pid = fork();
        if (pid < 0) return 127;

        if (pid == 0) {
            int devnull = open("/dev/null", O_WRONLY);
            if (devnull >= 0) {
                dup2(devnull, STDOUT_FILENO);
                dup2(devnull, STDERR_FILENO);
                close(devnull);
            }
            execvp(argv[0], argv.data());
            _exit(127);
        }

        int st = 0;
        while (waitpid(pid, &st, 0) < 0) {
            if (errno == EINTR) continue;
            return 127;
        }

        if (WIFEXITED(st)) return WEXITSTATUS(st);
        if (WIFSIGNALED(st)) return 128 + WTERMSIG(st);
        return 127;
    };

    auto generate_gallery_thumb = [&](const std::filesystem::path& src_abs,
                                      const std::filesystem::path& dst_abs,
                                      int size,
                                      std::string* err) -> bool {
        if (err) err->clear();

        const std::string size_arg = std::to_string(size) + "x" + std::to_string(size) + ">";
        std::vector<std::string> attempts;

        auto try_cmd = [&](const std::string& exe) -> bool {
            std::vector<std::string> args = {
                exe,
                src_abs.string(),
                "-auto-orient",
                "-thumbnail", size_arg,
                "-strip",
                "-quality", "82",
                dst_abs.string()
            };

            const int rc = spawn_wait(args);
            attempts.push_back(exe + "=" + std::to_string(rc));

            if (rc != 0) return false;

            std::error_code ec;
            auto st = std::filesystem::symlink_status(dst_abs, ec);
            return !ec && std::filesystem::exists(st) &&
                   !std::filesystem::is_symlink(st) &&
                   std::filesystem::is_regular_file(st);
        };

        if (try_cmd("/usr/bin/magick")) return true;
        if (try_cmd("/usr/local/bin/magick")) return true;
        if (try_cmd("magick")) return true;
        if (try_cmd("/usr/bin/convert")) return true;
        if (try_cmd("/usr/local/bin/convert")) return true;
        if (try_cmd("convert")) return true;

        if (err) {
            std::string joined;
            for (size_t i = 0; i < attempts.size(); ++i) {
                if (i) joined += ", ";
                joined += attempts[i];
            }
            *err = "thumbnail generator failed: " + joined;
        }
        return false;
    };

    auto cache_root = [&]() -> std::filesystem::path {
        return std::filesystem::path(pqnas::data_root_dir()).parent_path() / "cache" / "gallery_thumbs";
    };

    {
        auto uopt = users.get(fp_hex);
        if (!uopt.has_value() || uopt->storage_state != "allocated") {
            audit_fail("storage_unallocated", 403);
            reply_json(res, 403, json{
                {"ok", false},
                {"error", "storage_unallocated"},
                {"message", "Storage not allocated"}
            }.dump());
            return;
        }
    }

    std::string rel_path;
    if (req.has_param("path")) rel_path = req.get_param_value("path");
    if (rel_path.empty()) {
        audit_fail("missing_path", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "missing path"}
        }.dump());
        return;
    }

    std::string rel_norm;
    {
        std::string nerr;
        if (!pqnas::normalize_user_rel_path_strict(rel_path, &rel_norm, &nerr)) {
            audit_fail("invalid_path", 400, nerr);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "invalid path"}
            }.dump());
            return;
        }
    }

    int thumb_size = 320;
    if (req.has_param("size")) {
        try {
            thumb_size = std::stoi(req.get_param_value("size"));
        } catch (...) {
            thumb_size = 320;
        }
    }
    if (thumb_size < 64) thumb_size = 64;
    if (thumb_size > 1024) thumb_size = 1024;

    pqnas::ResolvedExistingPath rp;
    std::string perr;
    if (!pqnas::resolve_existing_user_file_path(users, fp_hex, rel_path, &rp, &perr)) {
        audit_fail("invalid_path", 400, perr);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid path"}
        }.dump());
        return;
    }

    const std::filesystem::path abs = rp.abs_path;

    {
        std::string serr;
        if (!ensure_no_symlink_in_existing_path_prefix(abs, &serr)) {
            audit_fail("symlink_not_supported", 400, serr);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "symlinks not supported"}
            }.dump());
            return;
        }
    }

    std::error_code ec;
    auto st = std::filesystem::symlink_status(abs, ec);
    if (ec || !std::filesystem::exists(st)) {
        audit_fail("not_found", 404);
        reply_json(res, 404, json{
            {"ok", false},
            {"error", "not_found"},
            {"message", "file not found"}
        }.dump());
        return;
    }

    if (std::filesystem::is_symlink(st)) {
        audit_fail("symlink_not_supported", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "symlinks not supported"}
        }.dump());
        return;
    }

    if (!std::filesystem::is_regular_file(st)) {
        audit_fail("not_regular_file", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "not a regular file"}
        }.dump());
        return;
    }

    if (!is_supported_gallery_thumb_ext(abs.filename().string())) {
        audit_fail("unsupported_image_type", 415, abs.filename().string());
        reply_json(res, 415, json{
            {"ok", false},
            {"error", "unsupported_media_type"},
            {"message", "unsupported image type"}
        }.dump());
        return;
    }

    const std::uint64_t src_bytes = pqnas::file_size_u64_safe(abs);
    const std::int64_t src_mtime = file_mtime_epoch(abs);

    const std::string key_material =
        fp_hex + "\n" +
        rel_norm + "\n" +
        std::to_string(thumb_size) + "\n" +
        std::to_string((unsigned long long)src_bytes) + "\n" +
        std::to_string((long long)src_mtime);

    const std::string thumb_key = hex_u64(fnv1a64(key_material));

    const std::filesystem::path cache_dir =
        cache_root() / fp_hex / std::to_string(thumb_size);
    const std::filesystem::path cache_abs = cache_dir / (thumb_key + ".jpg");

    auto serve_thumb = [&](bool cached) {
        std::string buf;
        std::string rerr;
        if (!read_small_file(cache_abs, &buf, &rerr)) {
            audit_fail("thumb_read_failed", 500, rerr);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "failed to read thumbnail"},
                {"detail", pqnas::shorten(rerr, 180)}
            }.dump());
            return;
        }

        const std::uint64_t out_bytes = static_cast<std::uint64_t>(buf.size());
        res.set_header("Cache-Control", "private, max-age=86400");
        res.set_content(std::move(buf), "image/jpeg");
        audit_ok(rel_norm, cached, out_bytes);
    };

    {
        std::error_code cec;
        auto cst = std::filesystem::symlink_status(cache_abs, cec);
        if (!cec &&
            std::filesystem::exists(cst) &&
            !std::filesystem::is_symlink(cst) &&
            std::filesystem::is_regular_file(cst)) {
            serve_thumb(true);
            return;
        }
    }

    ec.clear();
    std::filesystem::create_directories(cache_dir, ec);
    if (ec) {
        audit_fail("cache_mkdir_failed", 500, ec.message());
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "failed to create thumbnail cache directory"},
            {"detail", pqnas::shorten(ec.message(), 180)}
        }.dump());
        return;
    }

    const std::filesystem::path tmp_abs =
        cache_dir / (thumb_key + ".tmp." + random_b64url(8) + ".jpg");

    std::string terr;
    if (!generate_gallery_thumb(abs, tmp_abs, thumb_size, &terr)) {
        std::error_code rm_ec;
        std::filesystem::remove(tmp_abs, rm_ec);

        audit_fail("thumb_generate_failed", 500, terr);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "failed to generate thumbnail"},
            {"detail", pqnas::shorten(terr, 180)}
        }.dump());
        return;
    }

    {
        std::error_code ren_ec;
        std::filesystem::rename(tmp_abs, cache_abs, ren_ec);
        if (ren_ec) {
            std::error_code cec;
            auto cst = std::filesystem::symlink_status(cache_abs, cec);

            if (!cec &&
                std::filesystem::exists(cst) &&
                !std::filesystem::is_symlink(cst) &&
                std::filesystem::is_regular_file(cst)) {
                std::error_code rm_ec;
                std::filesystem::remove(tmp_abs, rm_ec);
            } else {
                std::error_code rm_ec;
                std::filesystem::remove(tmp_abs, rm_ec);

                audit_fail("thumb_rename_failed", 500, ren_ec.message());
                reply_json(res, 500, json{
                    {"ok", false},
                    {"error", "server_error"},
                    {"message", "failed to finalize thumbnail"},
                    {"detail", pqnas::shorten(ren_ec.message(), 180)}
                }.dump());
                return;
            }
        }
    }

    serve_thumb(false);
});

    auto trim_ascii_ws_copy = [](std::string s) -> std::string {
    auto is_ws = [](unsigned char c) -> bool {
        return c == ' ' || c == '\t' || c == '\r' || c == '\n';
    };

    std::size_t a = 0;
    while (a < s.size() && is_ws((unsigned char)s[a])) ++a;

    std::size_t b = s.size();
    while (b > a && is_ws((unsigned char)s[b - 1])) --b;

    return s.substr(a, b - a);
};

auto split_gallery_keywords_text = [&](const std::string& s) -> std::vector<std::string> {
    std::vector<std::string> out;

    std::size_t start = 0;
    while (start <= s.size()) {
        const std::size_t comma = s.find(',', start);

        std::string part = (comma == std::string::npos)
            ? s.substr(start)
            : s.substr(start, comma - start);

        part = trim_ascii_ws_copy(part);
        if (!part.empty()) out.push_back(part);

        if (comma == std::string::npos) break;
        start = comma + 1;
    }

    return out;
};

auto join_gallery_keywords_json = [&](const json& jv, std::string* err) -> std::string {
    if (!jv.is_array()) {
        if (err) *err = "meta.keywords must be an array";
        return "";
    }

    std::string out;
    bool first = true;

    for (const auto& it : jv) {
        if (!it.is_string()) {
            if (err) *err = "meta.keywords entries must be strings";
            return "";
        }

        std::string s = trim_ascii_ws_copy(it.get<std::string>());
        if (s.empty()) continue;
        if (s.size() > 256) s.resize(256);

        if (!first) out += ", ";
        out += s;
        first = false;

        if (out.size() > 4000) {
            out.resize(4000);
            break;
        }
    }

    return out;
};

auto extract_gallery_description_json = [&](const json& jv, std::string* err) -> std::string {
    if (jv.is_string()) {
        std::string s = jv.get<std::string>();
        if (s.size() > 12000) s.resize(12000);
        return s;
    }

    if (!jv.is_object()) {
        if (err) *err = "meta.description must be an object";
        return "";
    }

    auto it = jv.find("x-default");
    if (it == jv.end() || it->is_null()) {
        return "";
    }

    if (!it->is_string()) {
        if (err) *err = "meta.description.x-default must be a string";
        return "";
    }

    std::string s = it->get<std::string>();
    if (s.size() > 12000) s.resize(12000);
    return s;
};

auto make_gallery_meta_api_json = [&](int rating,
                                      const std::string& tags_text,
                                      const std::string& notes_text,
                                      std::uint64_t size_bytes,
                                      std::int64_t mtime_epoch,
                                      std::int64_t created_epoch,
                                      std::int64_t updated_epoch) -> json {
    return json{
        {"title", json{{"x-default", ""}}},
        {"description", json{{"x-default", notes_text}}},
        {"keywords", split_gallery_keywords_text(tags_text)},
        {"imageRating", rating},

        // keep old fields too for compatibility
        {"rating", rating},
        {"tags_text", tags_text},
        {"notes_text", notes_text},

        {"size_bytes", size_bytes},
        {"mtime_epoch", mtime_epoch},
        {"created_epoch", created_epoch},
        {"updated_epoch", updated_epoch}
    };
};

    // POST /api/v4/gallery/meta/set
    // Accepts old shape:
    // {
    //   "path": "photos/cat.jpg",
    //   "rating": 5,
    //   "tags_text": "cat, sofa",
    //   "notes_text": "best shot"
    // }
    //
    // Also accepts new shape:
    // {
    //   "path": "photos/cat.jpg",
    //   "meta": {
    //     "imageRating": 5,
    //     "keywords": ["cat", "sofa"],
    //     "description": {
    //       "x-default": "best shot"
    //     }
    //   }
    // }
srv.Post("/api/v4/gallery/meta/set", [&](const httplib::Request& req, httplib::Response& res) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;

    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto add_ip_headers = [&](pqnas::AuditEvent& ev) {
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
    };

    auto audit_fail = [&](const std::string& reason, int http,
                          const std::string& detail = "",
                          const std::string& rel_path = "") {
        pqnas::AuditEvent ev;
        ev.event = "v4.gallery_meta_set_fail";
        ev.outcome = "fail";
        ev.f["fingerprint"] = fp_hex;
        ev.f["reason"] = reason;
        ev.f["http"] = std::to_string(http);
        if (!rel_path.empty()) ev.f["path"] = pqnas::shorten(rel_path, 200);
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);
        add_ip_headers(ev);
        audit_append(ev);
    };

    auto audit_ok = [&](const std::string& rel_path,
                        bool rating_changed,
                        bool tags_changed,
                        bool notes_changed) {
        pqnas::AuditEvent ev;
        ev.event = "v4.gallery_meta_set_ok";
        ev.outcome = "ok";
        ev.f["fingerprint"] = fp_hex;
        ev.f["path"] = pqnas::shorten(rel_path, 200);
        ev.f["rating_changed"] = rating_changed ? "1" : "0";
        ev.f["tags_changed"] = tags_changed ? "1" : "0";
        ev.f["notes_changed"] = notes_changed ? "1" : "0";
        add_ip_headers(ev);
        audit_append(ev);
    };

    // allocated storage required
    {
        auto uopt = users.get(fp_hex);
        if (!uopt.has_value()) {
            audit_fail("user_missing", 403);
            reply_json(res, 403, json{
                {"ok", false},
                {"error", "forbidden"},
                {"message", "policy denied"}
            }.dump());
            return;
        }

        const auto& u = *uopt;
        if (u.storage_state != "allocated") {
            audit_fail("storage_unallocated", 403);
            reply_json(res, 403, json{
                {"ok", false},
                {"error", "storage_unallocated"},
                {"message", "Storage not allocated"},
                {"fingerprint_hex", fp_hex},
                {"quota_bytes", u.quota_bytes}
            }.dump());
            return;
        }
    }

    json in = json::parse(req.body, nullptr, false);
    if (in.is_discarded() || !in.is_object()) {
        audit_fail("bad_json", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid json body"}
        }.dump());
        return;
    }

    const std::string path_in = in.value("path", "");
    if (path_in.empty()) {
        audit_fail("missing_path", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "missing path"}
        }.dump());
        return;
    }

    std::string rel_norm;
    std::string nerr;
    if (!pqnas::normalize_user_rel_path_strict(path_in, &rel_norm, &nerr)) {
        audit_fail("invalid_path", 400, nerr, path_in);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid path"}
        }.dump());
        return;
    }

    const bool has_meta = in.contains("meta");
json meta_in = json::object();

if (has_meta) {
    if (!in["meta"].is_object()) {
        audit_fail("bad_meta", 400, "", rel_norm);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "meta must be an object"}
        }.dump());
        return;
    }
    meta_in = in["meta"];
}

const bool has_rating_old = in.contains("rating");
const bool has_tags_old = in.contains("tags_text");
const bool has_notes_old = in.contains("notes_text");

const bool has_rating_new = has_meta && meta_in.contains("imageRating");
const bool has_tags_new = has_meta && meta_in.contains("keywords");
const bool has_notes_new = has_meta && meta_in.contains("description");

const bool has_rating = has_rating_old || has_rating_new;
const bool has_tags = has_tags_old || has_tags_new;
const bool has_notes = has_notes_old || has_notes_new;

if (!has_rating && !has_tags && !has_notes) {
    audit_fail("no_fields", 400, "", rel_norm);
    reply_json(res, 400, json{
        {"ok", false},
        {"error", "bad_request"},
        {"message", "nothing to update"}
    }.dump());
    return;
}

std::optional<int> rating;
std::optional<std::string> tags_text;
std::optional<std::string> notes_text;

if (has_rating) {
    if (has_rating_new) {
        if (!meta_in["imageRating"].is_number_integer()) {
            audit_fail("bad_imageRating", 400, "", rel_norm);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "meta.imageRating must be an integer"}
            }.dump());
            return;
        }

        int r = meta_in["imageRating"].get<int>();
        if (r < 0) r = 0;
        if (r > 5) r = 5;
        rating = r;
    } else {
        if (!in["rating"].is_number_integer()) {
            audit_fail("bad_rating", 400, "", rel_norm);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "rating must be an integer"}
            }.dump());
            return;
        }

        int r = in["rating"].get<int>();
        if (r < 0) r = 0;
        if (r > 5) r = 5;
        rating = r;
    }
}

if (has_tags) {
    if (has_tags_new) {
        std::string perr;
        auto s = join_gallery_keywords_json(meta_in["keywords"], &perr);
        if (!perr.empty()) {
            audit_fail("bad_keywords", 400, perr, rel_norm);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", perr}
            }.dump());
            return;
        }
        tags_text = s;
    } else {
        if (!in["tags_text"].is_string()) {
            audit_fail("bad_tags_text", 400, "", rel_norm);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "tags_text must be a string"}
            }.dump());
            return;
        }

        auto s = in["tags_text"].get<std::string>();
        if (s.size() > 4000) s.resize(4000);
        tags_text = s;
    }
}

if (has_notes) {
    if (has_notes_new) {
        std::string perr;
        auto s = extract_gallery_description_json(meta_in["description"], &perr);
        if (!perr.empty()) {
            audit_fail("bad_description", 400, perr, rel_norm);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", perr}
            }.dump());
            return;
        }
        notes_text = s;
    } else {
        if (!in["notes_text"].is_string()) {
            audit_fail("bad_notes_text", 400, "", rel_norm);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "notes_text must be a string"}
            }.dump());
            return;
        }

        auto s = in["notes_text"].get<std::string>();
        if (s.size() > 12000) s.resize(12000);
        notes_text = s;
    }
}

    // verify target exists and is a file
    pqnas::ResolvedLogicalItem item;
    std::string rerr;
    if (!pqnas::resolve_existing_user_item(users, fp_hex, rel_norm, &item, &rerr) || !item.exists) {
        audit_fail("not_found", 404, rerr, rel_norm);
        reply_json(res, 404, json{
            {"ok", false},
            {"error", "not_found"},
            {"message", "path not found"}
        }.dump());
        return;
    }

    if (!item.is_file) {
        audit_fail("not_file", 400, "", rel_norm);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "gallery metadata can only be set for files"}
        }.dump());
        return;
    }

    auto lower_ascii_local = [](std::string s) -> std::string {
        for (char& c : s) c = (char)std::tolower((unsigned char)c);
        return s;
    };

    auto file_ext_lower = [&](const std::string& name) -> std::string {
        std::string n = name;
        const auto slash = n.find_last_of("/\\");
        if (slash != std::string::npos) n = n.substr(slash + 1);
        auto lower = lower_ascii_local(n);
        const auto dot = lower.rfind('.');
        if (dot == std::string::npos || dot == 0 || dot + 1 >= lower.size()) return "";
        return lower.substr(dot + 1);
    };

    auto is_gallery_image_name = [&](const std::string& name) -> bool {
        const std::string ext = file_ext_lower(name);
        return ext == "png"  ||
               ext == "jpg"  ||
               ext == "jpeg" ||
               ext == "gif"  ||
               ext == "webp" ||
               ext == "svg"  ||
               ext == "bmp"  ||
               ext == "ico"  ||
               ext == "tif"  ||
               ext == "tiff" ||
               ext == "heic" ||
               ext == "heif" ||
               ext == "cr2"  ||
               ext == "cr3"  ||
               ext == "nef"  ||
               ext == "arw"  ||
               ext == "raf"  ||
               ext == "dng"  ||
               ext == "rw2"  ||
               ext == "orf";
    };

    if (!is_gallery_image_name(std::filesystem::path(rel_norm).filename().string())) {
        audit_fail("not_supported_image", 400, "", rel_norm);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "file is not a supported gallery image"}
        }.dump());
        return;
    }

    auto* gidx = pqnas::get_gallery_meta_index();
    if (!gidx) {
        audit_fail("gallery_meta_index_missing", 500, "", rel_norm);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "gallery metadata index missing"}
        }.dump());
        return;
    }

    std::uint64_t size_bytes = 0;
    std::int64_t mtime_epoch = 0;

    {
        auto* idx = pqnas::get_file_location_index();
        if (idx) {
            std::string lerr;
            auto rec = idx->get(fp_hex, rel_norm, &lerr);
            if (!lerr.empty()) {
                audit_fail("file_location_lookup_failed", 500, lerr, rel_norm);
                reply_json(res, 500, json{
                    {"ok", false},
                    {"error", "server_error"},
                    {"message", "file metadata lookup failed"},
                    {"detail", pqnas::shorten(lerr, 180)}
                }.dump());
                return;
            }
            if (rec.has_value()) {
                size_bytes = rec->size_bytes;
                mtime_epoch = rec->mtime_epoch;
            }
        }
    }

    // fallback to physical file stat if needed
    if ((size_bytes == 0 || mtime_epoch == 0) && item.has_physical_anchor) {
        std::error_code ec;
        auto st = std::filesystem::symlink_status(item.abs_path, ec);
        if (!ec && std::filesystem::exists(st) && std::filesystem::is_regular_file(st)) {
            if (size_bytes == 0) {
                size_bytes = pqnas::file_size_u64_safe(item.abs_path);
            }
            if (mtime_epoch == 0) {
                auto ft = std::filesystem::last_write_time(item.abs_path, ec);
                if (!ec) {
                    using namespace std::chrono;
                    auto sctp = time_point_cast<system_clock::duration>(
                        ft - std::filesystem::file_time_type::clock::now() + system_clock::now()
                    );
                    mtime_epoch = (std::int64_t)duration_cast<seconds>(sctp.time_since_epoch()).count();
                }
            }
        }
    }

    const std::int64_t now_ts = now_epoch_sec();

    std::string gerr;
    if (!gidx->patch("user", fp_hex, rel_norm, rating, tags_text, notes_text, now_ts, &gerr)) {
        audit_fail("gallery_meta_patch_failed", 500, gerr, rel_norm);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "gallery metadata update failed"},
            {"detail", pqnas::shorten(gerr, 180)}
        }.dump());
        return;
    }

    // best-effort touch so cached file facts stay current on existing/new row
    {
        std::string terr;
        (void)gidx->touch_file_facts("user", fp_hex, rel_norm, size_bytes, mtime_epoch, now_ts, &terr);
    }

    std::string get_err;
    auto out_rec = gidx->get("user", fp_hex, rel_norm, &get_err);
    if (!get_err.empty()) {
        audit_fail("gallery_meta_readback_failed", 500, get_err, rel_norm);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "gallery metadata readback failed"},
            {"detail", pqnas::shorten(get_err, 180)}
        }.dump());
        return;
    }

    audit_ok(rel_norm, has_rating, has_tags, has_notes);

    int final_rating = rating.has_value() ? *rating : 0;
    std::string final_tags_text = tags_text.has_value() ? *tags_text : "";
    std::string final_notes_text = notes_text.has_value() ? *notes_text : "";
    std::uint64_t final_size_bytes = size_bytes;
    std::int64_t final_mtime_epoch = mtime_epoch;
    std::int64_t final_created_epoch = 0;
    std::int64_t final_updated_epoch = now_ts;

    if (out_rec.has_value()) {
        final_rating = out_rec->rating;
        final_tags_text = out_rec->tags_text;
        final_notes_text = out_rec->notes_text;
        final_size_bytes = out_rec->size_bytes;
        final_mtime_epoch = out_rec->mtime_epoch;
        final_created_epoch = out_rec->created_epoch;
        final_updated_epoch = out_rec->updated_epoch;
    }

    json out{
        {"ok", true},
        {"path", rel_norm},
        {"meta", make_gallery_meta_api_json(
            final_rating,
            final_tags_text,
            final_notes_text,
            final_size_bytes,
            final_mtime_epoch,
            final_created_epoch,
            final_updated_epoch
        )},
        {"file", json{
            {"size_bytes", final_size_bytes},
            {"mtime_epoch", final_mtime_epoch}
        }}
    };

    reply_json(res, 200, out.dump());

    reply_json(res, 200, out.dump());
});

    // POST /api/v4/gallery/meta/get
    // Body:
    // {
    //   "path": "photos/cat.jpg"
    // }
    //
    // Response includes both old compatibility fields:
    //   rating, tags_text, notes_text
    //
    // and new standardized fields:
    //   meta.imageRating
    //   meta.keywords[]
    //   meta.description["x-default"]
srv.Post("/api/v4/gallery/meta/get", [&](const httplib::Request& req, httplib::Response& res) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;

    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto add_ip_headers = [&](pqnas::AuditEvent& ev) {
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
    };

    auto audit_fail = [&](const std::string& reason, int http,
                          const std::string& detail = "",
                          const std::string& rel_path = "") {
        pqnas::AuditEvent ev;
        ev.event = "v4.gallery_meta_get_fail";
        ev.outcome = "fail";
        ev.f["fingerprint"] = fp_hex;
        ev.f["reason"] = reason;
        ev.f["http"] = std::to_string(http);
        if (!rel_path.empty()) ev.f["path"] = pqnas::shorten(rel_path, 200);
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);
        add_ip_headers(ev);
        audit_append(ev);
    };

    auto audit_ok = [&](const std::string& rel_path, bool found_meta) {
        pqnas::AuditEvent ev;
        ev.event = "v4.gallery_meta_get_ok";
        ev.outcome = "ok";
        ev.f["fingerprint"] = fp_hex;
        ev.f["path"] = pqnas::shorten(rel_path, 200);
        ev.f["found_meta"] = found_meta ? "1" : "0";
        add_ip_headers(ev);
        audit_append(ev);
    };

    auto lower_ascii_local = [](std::string s) -> std::string {
        for (char& c : s) c = (char)std::tolower((unsigned char)c);
        return s;
    };

    auto file_ext_lower = [&](const std::string& name) -> std::string {
        std::string n = name;
        const auto slash = n.find_last_of("/\\");
        if (slash != std::string::npos) n = n.substr(slash + 1);
        auto lower = lower_ascii_local(n);
        const auto dot = lower.rfind('.');
        if (dot == std::string::npos || dot == 0 || dot + 1 >= lower.size()) return "";
        return lower.substr(dot + 1);
    };

    auto is_gallery_image_name = [&](const std::string& name) -> bool {
        const std::string ext = file_ext_lower(name);
        return ext == "png"  ||
               ext == "jpg"  ||
               ext == "jpeg" ||
               ext == "gif"  ||
               ext == "webp" ||
               ext == "svg"  ||
               ext == "bmp"  ||
               ext == "ico"  ||
               ext == "tif"  ||
               ext == "tiff" ||
               ext == "heic" ||
               ext == "heif" ||
               ext == "cr2"  ||
               ext == "cr3"  ||
               ext == "nef"  ||
               ext == "arw"  ||
               ext == "raf"  ||
               ext == "dng"  ||
               ext == "rw2"  ||
               ext == "orf";
    };

    // allocated storage required
    {
        auto uopt = users.get(fp_hex);
        if (!uopt.has_value()) {
            audit_fail("user_missing", 403);
            reply_json(res, 403, json{
                {"ok", false},
                {"error", "forbidden"},
                {"message", "policy denied"}
            }.dump());
            return;
        }

        const auto& u = *uopt;
        if (u.storage_state != "allocated") {
            audit_fail("storage_unallocated", 403);
            reply_json(res, 403, json{
                {"ok", false},
                {"error", "storage_unallocated"},
                {"message", "Storage not allocated"},
                {"fingerprint_hex", fp_hex},
                {"quota_bytes", u.quota_bytes}
            }.dump());
            return;
        }
    }

    json in = json::parse(req.body, nullptr, false);
    if (in.is_discarded() || !in.is_object()) {
        audit_fail("bad_json", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid json body"}
        }.dump());
        return;
    }

    const std::string path_in = in.value("path", "");
    if (path_in.empty()) {
        audit_fail("missing_path", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "missing path"}
        }.dump());
        return;
    }

    std::string rel_norm;
    std::string nerr;
    if (!pqnas::normalize_user_rel_path_strict(path_in, &rel_norm, &nerr)) {
        audit_fail("invalid_path", 400, nerr, path_in);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid path"}
        }.dump());
        return;
    }

    pqnas::ResolvedLogicalItem item;
    std::string rerr;
    if (!pqnas::resolve_existing_user_item(users, fp_hex, rel_norm, &item, &rerr) || !item.exists) {
        audit_fail("not_found", 404, rerr, rel_norm);
        reply_json(res, 404, json{
            {"ok", false},
            {"error", "not_found"},
            {"message", "path not found"}
        }.dump());
        return;
    }

    if (!item.is_file) {
        audit_fail("not_file", 400, "", rel_norm);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "gallery metadata is only available for files"}
        }.dump());
        return;
    }

    if (!is_gallery_image_name(std::filesystem::path(rel_norm).filename().string())) {
        audit_fail("not_supported_image", 400, "", rel_norm);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "file is not a supported gallery image"}
        }.dump());
        return;
    }

    std::uint64_t size_bytes = 0;
    std::int64_t mtime_epoch = 0;

    {
        auto* idx = pqnas::get_file_location_index();
        if (idx) {
            std::string lerr;
            auto rec = idx->get(fp_hex, rel_norm, &lerr);
            if (!lerr.empty()) {
                audit_fail("file_location_lookup_failed", 500, lerr, rel_norm);
                reply_json(res, 500, json{
                    {"ok", false},
                    {"error", "server_error"},
                    {"message", "file metadata lookup failed"},
                    {"detail", pqnas::shorten(lerr, 180)}
                }.dump());
                return;
            }
            if (rec.has_value()) {
                size_bytes = rec->size_bytes;
                mtime_epoch = rec->mtime_epoch;
            }
        }
    }

    if ((size_bytes == 0 || mtime_epoch == 0) && item.has_physical_anchor) {
        std::error_code ec;
        auto st = std::filesystem::symlink_status(item.abs_path, ec);
        if (!ec && std::filesystem::exists(st) && std::filesystem::is_regular_file(st)) {
            if (size_bytes == 0) {
                size_bytes = pqnas::file_size_u64_safe(item.abs_path);
            }
            if (mtime_epoch == 0) {
                auto ft = std::filesystem::last_write_time(item.abs_path, ec);
                if (!ec) {
                    using namespace std::chrono;
                    auto sctp = time_point_cast<system_clock::duration>(
                        ft - std::filesystem::file_time_type::clock::now() + system_clock::now()
                    );
                    mtime_epoch = (std::int64_t)duration_cast<seconds>(sctp.time_since_epoch()).count();
                }
            }
        }
    }

    auto* gidx = pqnas::get_gallery_meta_index();
    if (!gidx) {
        audit_fail("gallery_meta_index_missing", 500, "", rel_norm);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "gallery metadata index missing"}
        }.dump());
        return;
    }

    std::string gerr;
    auto meta = gidx->get("user", fp_hex, rel_norm, &gerr);
    if (!gerr.empty()) {
        audit_fail("gallery_meta_lookup_failed", 500, gerr, rel_norm);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "gallery metadata lookup failed"},
            {"detail", pqnas::shorten(gerr, 180)}
        }.dump());
        return;
    }

    const int final_rating = meta.has_value() ? meta->rating : 0;
    const std::string final_tags_text = meta.has_value() ? meta->tags_text : "";
    const std::string final_notes_text = meta.has_value() ? meta->notes_text : "";
    const std::uint64_t final_size_bytes =
        (meta.has_value() && meta->size_bytes > 0) ? meta->size_bytes : size_bytes;
    const std::int64_t final_mtime_epoch =
        (meta.has_value() && meta->mtime_epoch > 0) ? meta->mtime_epoch : mtime_epoch;
    const std::int64_t final_created_epoch = meta.has_value() ? meta->created_epoch : 0;
    const std::int64_t final_updated_epoch = meta.has_value() ? meta->updated_epoch : 0;

    json out{
        {"ok", true},
        {"path", rel_norm},
        {"meta", make_gallery_meta_api_json(
            final_rating,
            final_tags_text,
            final_notes_text,
            final_size_bytes,
            final_mtime_epoch,
            final_created_epoch,
            final_updated_epoch
        )},
        {"file", json{
            {"size_bytes", final_size_bytes},
            {"mtime_epoch", final_mtime_epoch}
        }}
    };

    audit_ok(rel_norm, meta.has_value());
    reply_json(res, 200, out.dump());
});
srv.Get("/api/v4/photogallery/stats", [&](const httplib::Request& req, httplib::Response& res) {
    std::string actor_fp, actor_role;
    if (!require_user_cookie_users_actor(req, res, COOKIE_KEY, &users, &actor_fp, &actor_role)) {
        return;
    }
    (void)actor_role;

    if (!users.load(users_path)) {
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "users_reload_failed"},
            {"message", "failed to reload users"}
        }.dump());
        return;
    }

    const auto uopt = users.get(actor_fp);
    if (!uopt.has_value()) {
        reply_json(res, 404, json{
            {"ok", false},
            {"error", "user_not_found"},
            {"message", "user not found"}
        }.dump());
        return;
    }

    const auto& user = *uopt;
    if (user.storage_state != "allocated" || user.root_rel.empty()) {
        reply_json(res, 200, json{
            {"ok", true},
            {"stats", {
                {"total_photos", 0},
                {"total_bytes", 0},
                {"total_megabytes", 0.0},
                {"photos_with_exif", 0},
                {"unique_cameras", 0},
                {"unique_lenses", 0},
                {"first_taken_at", ""},
                {"last_taken_at", ""},
                {"top_cameras", json::array()},
                {"top_lenses", json::array()},
                {"iso_buckets", json::array()},
                {"aperture_buckets", json::array()},
                {"shutter_buckets", json::array()},
                {"focal_length_buckets", json::array()},
                {"by_month", json::array()}
            }}
        }.dump());
        return;
    }

    bool path_ok = true;
    const std::string rel_sub =
        req.has_param("path")
            ? normalize_rel_subpath_for_stats(req.get_param_value("path"), &path_ok)
            : std::string();

    if (!path_ok) {
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid path"}
        }.dump());
        return;
    }

    const std::filesystem::path user_root =
        std::filesystem::path(pqnas::data_root_dir()) / user.root_rel;

    const std::filesystem::path scan_root =
        rel_sub.empty() ? user_root : (user_root / rel_sub);

    std::error_code ec;
    if (!std::filesystem::exists(scan_root, ec) || !std::filesystem::is_directory(scan_root, ec)) {
        reply_json(res, 200, json{
            {"ok", true},
            {"stats", {
                {"total_photos", 0},
                {"total_bytes", 0},
                {"total_megabytes", 0.0},
                {"photos_with_exif", 0},
                {"unique_cameras", 0},
                {"unique_lenses", 0},
                {"first_taken_at", ""},
                {"last_taken_at", ""},
                {"top_cameras", json::array()},
                {"top_lenses", json::array()},
                {"iso_buckets", json::array()},
                {"aperture_buckets", json::array()},
                {"shutter_buckets", json::array()},
                {"focal_length_buckets", json::array()},
                {"by_month", json::array()}
            }}
        }.dump());
        return;
    }

    sqlite3* db = nullptr;
    const std::filesystem::path db_path =
        std::filesystem::path(pqnas::data_root_dir()) / "photogallery_stats.sqlite3";

    if (sqlite3_open(db_path.string().c_str(), &db) != SQLITE_OK) {
        const std::string err = db ? sqlite3_errmsg(db) : "sqlite open failed";
        if (db) sqlite3_close(db);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "sqlite_open_failed"},
            {"message", err}
        }.dump());
        return;
    }

    std::string schema_err;
    if (!ensure_photo_stats_schema(db, &schema_err)) {
        sqlite3_close(db);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "sqlite_schema_failed"},
            {"message", schema_err}
        }.dump());
        return;
    }

    std::uint64_t total_photos = 0;
    std::uint64_t total_bytes = 0;
    std::uint64_t photos_with_exif = 0;

    std::set<std::string> unique_cameras;
    std::set<std::string> unique_lenses;

    std::map<std::string, int> top_cameras;
    std::map<std::string, int> top_lenses;
    std::map<std::string, int> iso_buckets;
    std::map<std::string, int> aperture_buckets;
    std::map<std::string, int> shutter_buckets;
    std::map<std::string, int> focal_buckets;
    std::map<std::string, int> by_month;

    std::string first_taken_at;
    std::string last_taken_at;

    const std::int64_t indexed_now = static_cast<std::int64_t>(std::time(nullptr));

    sqlite3_exec(db, "BEGIN IMMEDIATE TRANSACTION", nullptr, nullptr, nullptr);

    for (std::filesystem::recursive_directory_iterator it(scan_root, ec), end;
         it != end && !ec;
         it.increment(ec)) {
        if (ec) break;

        std::error_code ec2;
        if (!it->is_regular_file(ec2) || ec2) continue;

        const std::filesystem::path abs = it->path();
        if (!is_supported_photo_ext(abs)) continue;

        const std::string rel =
            std::filesystem::relative(abs, user_root, ec2).generic_string();
        if (ec2 || rel.empty()) continue;

        const std::uint64_t size_bytes = file_size_u64_safe_local(abs);
        const std::int64_t mtime_epoch = file_mtime_epoch_safe_local(abs);

        ++total_photos;
        total_bytes += size_bytes;

        PhotoStatsRow row;
        const bool have_cached = load_cached_photo_stats_row(db, rel, &row);
        const bool cache_match =
            have_cached &&
            row.size_bytes == size_bytes &&
            row.mtime_epoch == mtime_epoch;

        if (!cache_match) {
            row = exif_row_from_file(rel, abs, size_bytes, mtime_epoch);
            std::string upsert_err;
            (void)upsert_photo_stats_row(db, row, indexed_now, &upsert_err);
        }

        if (row.exif_ok) ++photos_with_exif;

        const std::string camera = camera_label_from_row(row);
        const std::string lens = lens_label_from_row(row);

        if (!camera.empty()) unique_cameras.insert(camera);
        if (!lens.empty()) unique_lenses.insert(lens);

        bump_bucket(top_cameras, camera);
        bump_bucket(top_lenses, lens);
        bump_bucket(iso_buckets, iso_bucket_from_row(row));
        bump_bucket(aperture_buckets, aperture_bucket_from_row(row));
        bump_bucket(shutter_buckets, shutter_bucket_from_row(row));
        bump_bucket(focal_buckets, focal_bucket_from_row(row));
        bump_bucket(by_month, row.taken_month);

        if (!row.taken_at.empty()) {
            if (first_taken_at.empty() || row.taken_at < first_taken_at) first_taken_at = row.taken_at;
            if (last_taken_at.empty() || row.taken_at > last_taken_at) last_taken_at = row.taken_at;
        }
    }

    sqlite3_exec(db, "COMMIT", nullptr, nullptr, nullptr);
    sqlite3_close(db);

    json stats;
    stats["total_photos"] = total_photos;
    stats["total_bytes"] = total_bytes;
    stats["total_megabytes"] =
        static_cast<double>(total_bytes) / (1024.0 * 1024.0);

    stats["photos_with_exif"] = photos_with_exif;
    stats["unique_cameras"] = static_cast<unsigned long long>(unique_cameras.size());
    stats["unique_lenses"] = static_cast<unsigned long long>(unique_lenses.size());
    stats["first_taken_at"] = first_taken_at;
    stats["last_taken_at"] = last_taken_at;

    stats["top_cameras"] = top_bucket_array(top_cameras, 10);
    stats["top_lenses"] = top_bucket_array(top_lenses, 10);
    stats["iso_buckets"] = top_bucket_array(iso_buckets, 12);
    stats["aperture_buckets"] = top_bucket_array(aperture_buckets, 12);
    stats["shutter_buckets"] = top_bucket_array(shutter_buckets, 12);
    stats["focal_length_buckets"] = top_bucket_array(focal_buckets, 12);

    {
        std::vector<std::pair<std::string, int>> months(by_month.begin(), by_month.end());
        std::sort(months.begin(), months.end(), [](const auto& a, const auto& b) {
            return a.first < b.first;
        });

        stats["by_month"] = json::array();
        for (const auto& kv : months) {
            stats["by_month"].push_back({
                {"label", kv.first},
                {"count", kv.second}
            });
        }
    }

    res.set_header("Cache-Control", "no-store");
    reply_json(res, 200, json{
        {"ok", true},
        {"path", rel_sub},
        {"stats", stats}
    }.dump());
});

// ---- Files API (user storage) ----
// PUT /api/v4/files/put?path=relative/path.bin[&overwrite=1]
// Body: raw bytes (streamed to temp file, then renamed atomically)
srv.Put("/api/v4/files/put",
    [&](const httplib::Request& req,
    httplib::Response& res,
    const httplib::ContentReader& content_reader) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;

    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto header_u64 = [&](const char* name, std::uint64_t* out) -> bool {
        if (!out) return false;
        auto it = req.headers.find(name);
        if (it == req.headers.end()) return false;
        const std::string& s = it->second;
        try {
            size_t idx = 0;
            unsigned long long v = std::stoull(s, &idx, 10);
            if (idx != s.size()) return false;
            *out = (std::uint64_t)v;
            return true;
        } catch (...) {
            return false;
        }
    };

    auto audit_fail = [&](const std::string& reason, int http, const std::string& detail = "") {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_put_fail";
        ev.outcome = "fail";
        ev.f["fingerprint"] = fp_hex;
        ev.f["reason"] = reason;
        ev.f["http"] = std::to_string(http);
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);

        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    auto audit_quota_deny = [&](const std::string& rel_path, const pqnas::QuotaCheckResult& qc) {
        pqnas::AuditEvent ev;
        ev.event = "user_storage_quota_exceeded";
        ev.outcome = "deny";
        ev.f["fingerprint"] = fp_hex;
        ev.f["path"] = pqnas::shorten(rel_path, 200);

        ev.f["used_bytes"] = std::to_string((unsigned long long)qc.used_bytes);
        ev.f["quota_bytes"] = std::to_string((unsigned long long)qc.quota_bytes);
        ev.f["incoming_bytes"] = std::to_string((unsigned long long)qc.incoming_bytes);
        ev.f["existing_bytes"] = std::to_string((unsigned long long)qc.existing_bytes);
        ev.f["would_used_bytes"] = std::to_string((unsigned long long)qc.would_used_bytes);

        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    auto audit_ok = [&](const std::string& rel_path, std::uint64_t bytes) {
        pqnas::AuditEvent ev;
        ev.event = "v4.files_put_ok";
        ev.outcome = "ok";
        ev.f["fingerprint"] = fp_hex;
        ev.f["path"] = pqnas::shorten(rel_path, 200);
        ev.f["bytes"] = std::to_string((unsigned long long)bytes);

        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };
    if (!require_same_origin_for_cookie_mutation(req, res)) {
        audit_fail("origin_mismatch", 403);
        return;
    }
    auto file_time_to_epoch_sec = [](const std::filesystem::file_time_type& ft) -> std::int64_t {
        using namespace std::chrono;
        const auto sctp = time_point_cast<system_clock::duration>(
            ft - std::filesystem::file_time_type::clock::now() + system_clock::now()
        );
        return (std::int64_t)duration_cast<seconds>(sctp.time_since_epoch()).count();
    };

    // path param
    std::string rel_path;
    if (req.has_param("path")) rel_path = req.get_param_value("path");
    if (rel_path.empty()) {
        audit_fail("missing_path", 400);
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "missing path"}
        }.dump());
        return;
    }

    std::string rel_norm;
    {
        std::string nerr;
        if (!pqnas::normalize_user_rel_path_strict(rel_path, &rel_norm, &nerr)) {
            audit_fail("invalid_path", 400, nerr);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "invalid path"}
            }.dump());
            return;
        }
    }

        bool overwrite = false;
        if (req.has_param("overwrite")) {
            const std::string ov = req.get_param_value("overwrite");
            overwrite = (ov == "1" || ov == "true" || ov == "yes");
        }

        std::cerr << "[put] rel_norm=" << rel_norm
                  << " overwrite=" << (overwrite ? 1 : 0)
                  << " overwrite_param="
                  << (req.has_param("overwrite") ? req.get_param_value("overwrite") : "<missing>")
                  << "\n";

    // Serialize writes on overlapping logical paths for this user.
    // This prevents PUT/MOVE/DELETE races on the same file/subtree.
    auto* plm = pqnas::get_path_lock_manager();
    auto write_guard = plm->lock_paths(fp_hex, {rel_norm});

    // Refuse uploads under a path whose ancestor is already a file.
    // Example: if "a" is a file, "a/b.txt" must be rejected.
    {
        std::string found_ancestor;
        std::string aerr;
        const bool conflict =
            pqnas::any_file_ancestor_exists(users, fp_hex, rel_norm, &found_ancestor, &aerr);

        if (!aerr.empty()) {
            audit_fail("ancestor_check_failed", 500, aerr);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "ancestor conflict check failed"},
                {"detail", pqnas::shorten(aerr, 180)}
            }.dump());
            return;
        }

        if (conflict) {
            audit_fail("ancestor_is_file", 409, found_ancestor);
            reply_json(res, 409, json{
                {"ok", false},
                {"error", "path_conflict"},
                {"message", "a parent path is an existing file"},
                {"ancestor", found_ancestor}
            }.dump());
            return;
        }
    }

    {
        auto* idx = pqnas::get_file_location_index();
        if (!idx) {
            audit_fail("metadata_index_missing", 500);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "metadata index missing"}
            }.dump());
            return;
        }

        std::string derr;
        const bool has_descendants = idx->logical_dir_exists(fp_hex, rel_norm, &derr);

        if (!derr.empty()) {
            audit_fail("descendant_check_failed", 500, derr);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "descendant conflict check failed"},
                {"detail", pqnas::shorten(derr, 180)}
            }.dump());
            return;
        }

        if (has_descendants) {
            audit_fail("path_has_descendants", 409, rel_norm);
            reply_json(res, 409, json{
                {"ok", false},
                {"error", "path_conflict"},
                {"message", "path already exists as a logical directory"},
                {"path", rel_norm}
            }.dump());
            return;
        }
    }

    // Require Content-Length for v1 streamer so quota can be checked before write.
    std::uint64_t cl = 0;
    if (!header_u64("Content-Length", &cl)) {
        audit_fail("missing_content_length", 411);
        reply_json(res, 411, json{
            {"ok", false},
            {"error", "length_required"},
            {"message", "Content-Length required"}
        }.dump());
        return;
    }

    const std::uint64_t incoming_bytes = cl;

    auto drain_request_body_best_effort = [&]() {
        try {
            content_reader([&](const char* /*data*/, size_t /*len*/) {
                return true; // consume and discard everything
            });
        } catch (...) {
            // best effort only
        }
    };

    // transport max (server-controlled, distinct from quota)
    const std::uint64_t transport_max =
        (g_transport_max_upload_bytes ? g_transport_max_upload_bytes : k_payload_max_upload_bytes);

    if (incoming_bytes > transport_max) {
        audit_fail("transport_limit_exceeded", 413,
                   "Content-Length=" + std::to_string((unsigned long long)incoming_bytes) +
                   " max=" + std::to_string((unsigned long long)transport_max));
        reply_json(res, 413, json{
            {"ok", false},
            {"error", "transport_limit_exceeded"},
            {"message", "Upload exceeds maximum allowed size"},
            {"content_length", incoming_bytes},
            {"max_bytes", transport_max},
            {"payload_max_upload_bytes", k_payload_max_upload_bytes}
        }.dump());
        return;
    }

    // quota + path resolve
    const std::filesystem::path user_dir = user_dir_for_fp(users, fp_hex);
    pqnas::QuotaCheckResult qc = pqnas::quota_check_for_upload_v1(
        users, fp_hex, user_dir, rel_path, incoming_bytes
    );

    if (!qc.ok) {
        if (qc.error == "quota_exceeded") audit_quota_deny(rel_path, qc);
        if (qc.error == "invalid_path") audit_fail("invalid_path", 400);
        if (qc.error != "storage_unallocated" && qc.error != "invalid_path" && qc.error != "quota_exceeded") {
            audit_fail("quota_check_failed", 403, qc.error);
        }
        if (reply_quota_error_v1(res, fp_hex, qc)) return;
    }

    const UploadTieringConfig tier_cfg = upload_tiering_config();

    std::cerr << "[tiering] enabled=" << (tier_cfg.enabled ? 1 : 0)
              << " landing_pool_id=" << tier_cfg.landing_pool_id << "\n";

    std::filesystem::path out_abs = qc.abs_path;
    bool tiering_write = false;

    std::cerr << "[put] qc.abs_path=" << qc.abs_path.string() << "\n";

    if (tier_cfg.enabled) {
        std::string terr;
        if (!build_landing_abs_path(tier_cfg.landing_pool_id, fp_hex, rel_norm, &out_abs, &terr)) {
            audit_fail("tiering_landing_pool_invalid", 500, terr);
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "tiering landing pool not found"},
                {"detail", pqnas::shorten(terr, 180)}
            }.dump());
            return;
        }
        tiering_write = true;
    }

    std::cerr << "[put] tiering_write=" << (tiering_write ? 1 : 0) << "\n";
    std::cerr << "[put] final out_abs=" << out_abs.string() << "\n";

    {
        std::string serr;
        if (!ensure_no_symlink_in_existing_path_prefix(out_abs.parent_path(), &serr)) {

            audit_fail("symlink_not_supported", 400, serr);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "symlinks not supported"},
                {"detail", serr}
            }.dump());
            return;
        }
    }

    // Detect existing logical file before writing.
    // Metadata index is authoritative for logical existence.
    auto* idx = pqnas::get_file_location_index();
    if (!idx) {
        audit_fail("metadata_index_missing", 500);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "metadata index missing"}
        }.dump());
        return;
    }

    std::optional<pqnas::FileLocationRecord> existing_rec;
    std::string existing_rec_err;
    existing_rec = idx->get(fp_hex, rel_norm, &existing_rec_err);
    if (!existing_rec_err.empty()) {
        audit_fail("metadata_lookup_failed", 500, existing_rec_err);
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "metadata lookup failed"},
            {"detail", pqnas::shorten(existing_rec_err, 180)}
        }.dump());
        return;
    }

    bool physical_exists_at_target = false;
    std::uint64_t physical_existing_size = 0;
    std::int64_t physical_existing_mtime = 0;

    {
        std::error_code ec;
        auto st = std::filesystem::symlink_status(out_abs, ec);
        if (ec) {
            if (ec != std::make_error_code(std::errc::no_such_file_or_directory)) {
                audit_fail("target_exists_check_failed", 500, ec.message());
                reply_json(res, 500, json{
                    {"ok", false},
                    {"error", "server_error"},
                    {"message", "target existence check failed"},
                    {"detail", pqnas::shorten(ec.message(), 180)}
                }.dump());
                return;
            }
            ec.clear();
        } else {
            physical_exists_at_target = std::filesystem::exists(st);

            if (physical_exists_at_target) {
                if (std::filesystem::is_symlink(st)) {
                    audit_fail("target_symlink_not_supported", 409, out_abs.string());
                    reply_json(res, 409, json{
                        {"ok", false},
                        {"error", "path_conflict"},
                        {"message", "target path exists as a symlink"},
                        {"path", rel_norm}
                    }.dump());
                    return;
                }

                if (!std::filesystem::is_regular_file(st)) {
                    audit_fail("target_not_regular_file", 409, out_abs.string());
                    reply_json(res, 409, json{
                        {"ok", false},
                        {"error", "path_conflict"},
                        {"message", "target path exists and is not a regular file"},
                        {"path", rel_norm}
                    }.dump());
                    return;
                }

                physical_existing_size = pqnas::file_size_u64_safe(out_abs);
                auto ft = std::filesystem::last_write_time(out_abs, ec);
                if (!ec) {
                    physical_existing_mtime = file_time_to_epoch_sec(ft);
                }
            }
        }
    }

        if (!overwrite && (existing_rec.has_value() || physical_exists_at_target)) {
            std::cerr << "[put] early conflict file_exists rel_norm=" << rel_norm << " draining body\n";

            drain_request_body_best_effort();

            json existing = json::object();

            if (existing_rec.has_value()) {
                existing["size_bytes"] = existing_rec->size_bytes;
                existing["mtime_epoch"] = existing_rec->mtime_epoch;
                existing["tier_state"] = existing_rec->tier_state;
                existing["current_pool"] = existing_rec->current_pool;
                existing["physical_path"] = existing_rec->physical_path;
            } else {
                existing["size_bytes"] = physical_existing_size;
                existing["mtime_epoch"] = physical_existing_mtime;
                existing["physical_path"] = out_abs.string();
            }

            audit_fail("file_exists", 409, rel_norm);
            reply_json(res, 409, json{
                {"ok", false},
                {"error", "file_exists"},
                {"message", "file already exists"},
                {"path", rel_norm},
                {"existing", existing}
            }.dump());
            return;
        }

    // Remember old physical path so overwrite to a different pool/path can clean it up later.
    std::string old_physical_path;
    if (existing_rec.has_value()) {
        old_physical_path = existing_rec->physical_path;
    } else if (physical_exists_at_target) {
        old_physical_path = out_abs.string();
    }

    // Ensure parent directory exists, but never through a symlinked parent chain.
    {
        std::string serr;
        if (!ensure_no_symlink_in_existing_path_prefix(out_abs.parent_path(), &serr)) {
            audit_fail("symlink_not_supported", 400, serr);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "symlinks not supported"}
            }.dump());
            return;
        }
    }

    {
        std::error_code ec;
        std::filesystem::create_directories(out_abs.parent_path(), ec);
        if (ec) {
            audit_fail("mkdir_failed", 500, ec.message());
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "failed to create directories"},
                {"detail", pqnas::shorten(ec.message(), 180)}
            }.dump());
            return;
        }
    }

    {
        std::string serr;
        if (!ensure_no_symlink_in_existing_path_prefix(out_abs.parent_path(), &serr)) {
            audit_fail("symlink_not_supported", 400, serr);
            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "symlinks not supported"}
            }.dump());
            return;
        }
    }

    // Temp write + rename
    const std::filesystem::path tmp =
        out_abs.parent_path() /
        (out_abs.filename().string() + ".upload." + random_b64url(8) + ".tmp");

    {
    std::error_code tmp_ec;
    auto tmp_st = std::filesystem::symlink_status(tmp, tmp_ec);
    if (!tmp_ec && std::filesystem::exists(tmp_st)) {
        if (std::filesystem::is_symlink(tmp_st)) {
            audit_fail("tmp_is_symlink", 409, tmp.string());
            reply_json(res, 409, json{
                {"ok", false},
                {"error", "path_conflict"},
                {"message", "temporary path is invalid"}
            }.dump());
            return;
        }

        if (!std::filesystem::is_regular_file(tmp_st)) {
            audit_fail("tmp_path_conflict", 409, tmp.string());
            reply_json(res, 409, json{
                {"ok", false},
                {"error", "path_conflict"},
                {"message", "temporary path is invalid"}
            }.dump());
            return;
        }

        std::filesystem::remove(tmp, tmp_ec);
        if (tmp_ec) {
            audit_fail("tmp_remove_failed", 500, tmp_ec.message());
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "failed to prepare temporary file"},
                {"detail", pqnas::shorten(tmp_ec.message(), 180)}
            }.dump());
            return;
        }
    }
}

    std::uint64_t bytes_written = 0;
    bool stream_ok = true;
    std::string stream_err;

    try {
        std::ofstream f(tmp, std::ios::binary | std::ios::trunc);
        if (!f.good()) {
            throw std::runtime_error("open tmp failed");
        }

        content_reader([&](const char* data, size_t len) {
            if (!stream_ok) return false;
            if (len == 0) return true;

            const std::uint64_t chunk = (std::uint64_t)len;
            const std::uint64_t next = bytes_written + chunk;

            if (next < bytes_written) {
                stream_ok = false;
                stream_err = "byte_count_overflow";
                return false;
            }

            if (next > incoming_bytes) {
                stream_ok = false;
                stream_err = "content_length_exceeded";
                return false;
            }

            if (next > transport_max) {
                stream_ok = false;
                stream_err = "transport_limit_exceeded";
                return false;
            }

            f.write(data, (std::streamsize)len);
            if (!f.good()) {
                stream_ok = false;
                stream_err = "write_tmp_failed";
                return false;
            }

            bytes_written = next;
            return true;
        });

        f.flush();
        if (!f.good()) {
            throw std::runtime_error("write tmp failed");
        }
        f.close();

        if (!stream_ok) {
            std::error_code ec;
            std::filesystem::remove(tmp, ec);

            const int http = (stream_err == "transport_limit_exceeded") ? 413 : 400;
            audit_fail(stream_err, http);

            reply_json(res, http, json{
                {"ok", false},
                {"error", (stream_err == "transport_limit_exceeded") ? "transport_limit_exceeded" : "bad_request"},
                {"message", stream_err},
                {"content_length", incoming_bytes},
                {"bytes_written", bytes_written}
            }.dump());
            return;
        }

        if (bytes_written != incoming_bytes) {
            std::error_code ec;
            std::filesystem::remove(tmp, ec);

            audit_fail("content_length_mismatch", 400,
                       "Content-Length=" + std::to_string((unsigned long long)incoming_bytes) +
                       " written=" + std::to_string((unsigned long long)bytes_written));

            reply_json(res, 400, json{
                {"ok", false},
                {"error", "bad_request"},
                {"message", "Content-Length mismatch"},
                {"content_length", incoming_bytes},
                {"bytes_written", bytes_written}
            }.dump());
            return;
        }

        std::cerr << "[put] tmp=" << tmp.string() << "\n";
        std::cerr << "[put] out_abs=" << out_abs.string() << "\n";
        std::cerr << "[put] tmp_exists=" << (std::filesystem::exists(tmp) ? 1 : 0) << "\n";
        std::cerr << "[put] out_parent=" << out_abs.parent_path().string() << "\n";
        std::cerr << "[put] out_parent_exists=" << (std::filesystem::exists(out_abs.parent_path()) ? 1 : 0) << "\n";

        {
            std::string serr;
            if (!ensure_no_symlink_in_existing_path_prefix(out_abs.parent_path(), &serr)) {
                std::error_code rm_ec;
                std::filesystem::remove(tmp, rm_ec);

                audit_fail("symlink_not_supported", 400, serr);
                reply_json(res, 400, json{
                    {"ok", false},
                    {"error", "bad_request"},
                    {"message", "symlinks not supported"}
                }.dump());
                return;
            }
        }

        {
        std::error_code dst_ec;
        auto dst_st = std::filesystem::symlink_status(out_abs, dst_ec);
        if (dst_ec) {
            if (dst_ec != std::make_error_code(std::errc::no_such_file_or_directory)) {
                std::error_code rm_ec;
                std::filesystem::remove(tmp, rm_ec);

                audit_fail("target_exists_check_failed", 500, dst_ec.message());
                reply_json(res, 500, json{
                    {"ok", false},
                    {"error", "server_error"},
                    {"message", "target existence check failed"},
                    {"detail", pqnas::shorten(dst_ec.message(), 180)}
                }.dump());
                return;
            }
            dst_ec.clear();
        } else if (std::filesystem::exists(dst_st)) {
            if (std::filesystem::is_symlink(dst_st)) {
                std::error_code rm_ec;
                std::filesystem::remove(tmp, rm_ec);

                audit_fail("target_symlink_not_supported", 409, out_abs.string());
                reply_json(res, 409, json{
                    {"ok", false},
                    {"error", "path_conflict"},
                    {"message", "target path exists as a symlink"},
                    {"path", rel_norm}
                }.dump());
                return;
            }

            if (!std::filesystem::is_regular_file(dst_st)) {
                std::error_code rm_ec;
                std::filesystem::remove(tmp, rm_ec);

                audit_fail("target_not_regular_file", 409, out_abs.string());
                reply_json(res, 409, json{
                    {"ok", false},
                    {"error", "path_conflict"},
                    {"message", "target path exists and is not a regular file"},
                    {"path", rel_norm}
                }.dump());
                return;
            }
        }
    }
        if (overwrite && (existing_rec.has_value() || physical_exists_at_target)) {
            const std::filesystem::path live_abs_to_preserve =
                !old_physical_path.empty() ? std::filesystem::path(old_physical_path) : out_abs;

            pqnas::PreserveLiveFileVersionParams vp;
            vp.scope_type = "user";
            vp.scope_id = fp_hex;
            vp.scope_root = user_dir;
            vp.logical_rel_path = rel_norm;
            vp.live_abs_path = live_abs_to_preserve;
            vp.event_kind = "overwrite_preserve";
            vp.actor_fp = fp_hex;
            vp.users = &users;

            pqnas::FileVersionRec vrec;
            std::string verr;
            if (!file_versions_index.preserve_live_file_version(vp, &vrec, &verr)) {
                std::error_code rm_ec;
                std::filesystem::remove(tmp, rm_ec);

                audit_fail("version_preserve_failed", 500, verr);
                reply_json(res, 500, json{
                    {"ok", false},
                    {"error", "server_error"},
                    {"message", "failed to preserve previous version"},
                    {"detail", pqnas::shorten(verr, 180)}
                }.dump());
                return;
            }
        }
        std::error_code rename_ec;
        std::filesystem::rename(tmp, out_abs, rename_ec);
        if (rename_ec) {
            std::error_code rm_ec;
            std::filesystem::remove(tmp, rm_ec);
            throw std::runtime_error(std::string("rename failed: ") + rename_ec.message());
        }

        {
            const std::int64_t now_ts = now_epoch_sec();

            pqnas::FileLocationRecord rec;
            rec.fp = fp_hex;
            rec.logical_rel_path = rel_norm;
            rec.current_pool = tiering_write ? tier_cfg.landing_pool_id : "";
            rec.physical_path = out_abs.string();
            rec.tier_state = tiering_write ? "landing" : "capacity";
            rec.size_bytes = bytes_written;
            rec.mtime_epoch = now_ts;
            rec.created_epoch = now_ts;
            rec.updated_epoch = now_ts;
            rec.version = 1;

            std::string merr;
            if (!idx->upsert_landing_file(rec, &merr)) {
                std::error_code ec2;
                std::filesystem::remove(out_abs, ec2);
                throw std::runtime_error(std::string("metadata upsert failed: ") + merr);
            }
            {
                std::string gerr;
                if (auto* gidx = pqnas::get_gallery_meta_index()) {
                    if (!gidx->touch_file_facts("user", fp_hex, rel_norm, bytes_written, now_ts, now_ts, &gerr)) {
                        // best-effort only; no hard fail
                    }
                }
            }
            if (tiering_write) {
                pqnas::AuditEvent tev;
                tev.event = "storage.tiering_upload_landed";
                tev.outcome = "ok";
                tev.f["fingerprint"] = fp_hex;
                tev.f["path"] = pqnas::shorten(rel_norm, 200);
                tev.f["tier_state"] = "landing";
                tev.f["pool_id"] = tier_cfg.landing_pool_id;
                tev.f["physical_path"] = pqnas::shorten(out_abs.string(), 220);
                tev.f["bytes"] = std::to_string((unsigned long long)bytes_written);

                tev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

                auto it_cf = req.headers.find("CF-Connecting-IP");
                if (it_cf != req.headers.end())
                    tev.f["cf_ip"] = it_cf->second;

                auto it_xff = req.headers.find("X-Forwarded-For");
                if (it_xff != req.headers.end())
                    tev.f["xff"] = pqnas::shorten(it_xff->second, 120);

                tev.f["ua"] = audit_ua();

                audit_append(tev);
            }
        }

        // If overwrite moved the logical file to a different physical path,
        // remove the old physical file after metadata points at the new one.
        if (!old_physical_path.empty()) {
            const std::string new_physical_path = out_abs.string();
            if (old_physical_path != new_physical_path) {
                std::error_code old_rm_ec;
                std::filesystem::remove(old_physical_path, old_rm_ec);
                if (old_rm_ec) {
                    pqnas::AuditEvent ev;
                    ev.event = "v4.files_put_old_physical_cleanup_fail";
                    ev.outcome = "warn";
                    ev.f["fingerprint"] = fp_hex;
                    ev.f["path"] = pqnas::shorten(rel_norm, 200);
                    ev.f["old_physical_path"] = pqnas::shorten(old_physical_path, 220);
                    ev.f["new_physical_path"] = pqnas::shorten(new_physical_path, 220);
                    ev.f["detail"] = pqnas::shorten(old_rm_ec.message(), 180);
                    ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;
                    ev.f["ua"] = audit_ua();
                    audit_append(ev);
                }
            }
        }

        audit_ok(rel_path, bytes_written);

        reply_json(res, 200, json{
            {"ok", true},
            {"fingerprint_hex", fp_hex},
            {"path", rel_path},
            {"bytes", bytes_written},
            {"overwrite", overwrite}
        }.dump());
        return;

    } catch (const std::exception& e) {
        std::error_code ec;
        std::filesystem::remove(tmp, ec);

        audit_fail("write_failed", 500, e.what());
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "upload failed"},
            {"detail", pqnas::shorten(e.what(), 180)}
        }.dump());
        return;
    }
});


srv.Get("/api/v4/files/versions/list", [&](const httplib::Request& req, httplib::Response& res) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;

    auto* vix = &file_versions_index;

    std::string path_rel;
    if (req.has_param("path")) path_rel = req.get_param_value("path");
    if (path_rel.empty()) {
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "missing path"}
        }.dump());
        return;
    }

    std::string rel_norm, nerr;
    if (!pqnas::normalize_user_rel_path_strict(path_rel, &rel_norm, &nerr)) {
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid path"}
        }.dump());
        return;
    }

    std::size_t limit = 100;
    if (req.has_param("limit")) {
        try {
            long long v = std::stoll(req.get_param_value("limit"));
            if (v > 0) limit = static_cast<std::size_t>(std::min<long long>(v, 500));
        } catch (...) {}
    }

    std::string verr;
    auto rows = vix->list_versions_for_path("user", fp_hex, rel_norm, limit, &verr);
    if (!verr.empty()) {
        reply_json(res, 500, json{
            {"ok", false},
            {"error", "server_error"},
            {"message", "failed to list file versions"},
            {"detail", pqnas::shorten(verr, 180)}
        }.dump());
        return;
    }

    json out;
    out["ok"] = true;
    out["scope_type"] = "user";
    out["scope_id"] = fp_hex;
    out["path"] = rel_norm;
    out["versions"] = json::array();

    for (const auto& r : rows) {
        json item = json::object();
        item["version_id"] = r.version_id;
        item["logical_rel_path"] = r.logical_rel_path;
        item["event_kind"] = r.event_kind;
        item["created_at"] = r.created_at;
        item["created_epoch"] = r.created_epoch;
        item["actor_fp"] = r.actor_fp;
        item["actor_name_snapshot"] = r.actor_name_snapshot;
        item["actor_display"] = pqnas::version_actor_display(r.actor_name_snapshot, r.actor_fp);
        item["bytes"] = r.bytes;
        item["sha256_hex"] = r.sha256_hex;
        item["is_deleted_event"] = (r.is_deleted_event != 0);

        out["versions"].push_back(std::move(item));
    }

    reply_json(res, 200, out.dump());
});

srv.Post("/api/v4/files/restore_version", [&](const httplib::Request& req, httplib::Response& res) {
    std::string fp_hex, role;
    if (!require_user_auth_users_actor(req, res, COOKIE_KEY, &users, &fp_hex, &role)) return;
    (void)role;

    json body = json::parse(req.body, nullptr, false);
    if (body.is_discarded() || !body.is_object()) {
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid json"}
        }.dump());
        return;
    }

    const std::string path_rel = body.value("path", "");
    const std::string version_id = body.value("version_id", "");

    if (path_rel.empty() || version_id.empty()) {
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "missing path or version_id"}
        }.dump());
        return;
    }

    std::string rel_norm, nerr;
    if (!pqnas::normalize_user_rel_path_strict(path_rel, &rel_norm, &nerr)) {
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid path"}
        }.dump());
        return;
    }

    const std::filesystem::path user_dir = user_dir_for_fp(users, fp_hex);

    std::filesystem::path abs_path;
    std::string perr;
    if (!pqnas::resolve_user_path_strict(user_dir, rel_norm, &abs_path, &perr)) {
        reply_json(res, 400, json{
            {"ok", false},
            {"error", "bad_request"},
            {"message", "invalid path"}
        }.dump());
        return;
    }
    std::string found_ancestor;
    std::string ancestor_err;
    if (pqnas::any_file_ancestor_exists(users, fp_hex, rel_norm, &found_ancestor, &ancestor_err)) {
        reply_json(res, 409, json{
            {"ok", false},
            {"error", "path_conflict"},
            {"message", "a parent path is an existing file"},
            {"ancestor", found_ancestor}
        }.dump());
        return;
    }

    auto uopt = users.get(fp_hex);
    if (!uopt.has_value() || uopt->storage_state != "allocated") {
        reply_json(res, 403, json{
            {"ok", false},
            {"error", "storage_unallocated"},
            {"message", "Storage not allocated"}
        }.dump());
        return;
    }

    auto* vix = &file_versions_index;

    std::error_code ec;
    auto live_st = std::filesystem::symlink_status(abs_path, ec);
    if (!ec && std::filesystem::exists(live_st) && !std::filesystem::is_symlink(live_st) && std::filesystem::is_regular_file(live_st)) {
        pqnas::PreserveCurrentVersionParams vp;
        vp.scope_type = "user";
        vp.scope_id = fp_hex;
        vp.scope_root = user_dir;
        vp.logical_rel_path = rel_norm;
        vp.live_abs_path = abs_path;
        vp.event_kind = "restore_preserve";
        vp.actor_fp = fp_hex;
        vp.users = &users;
        vp.file_versions = vix;

        std::string preserve_err;
        std::string ignored_version_id;
        if (!pqnas::preserve_current_file_version(vp, &ignored_version_id, &preserve_err)) {
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "failed to preserve current file before restore"},
                {"detail", pqnas::shorten(preserve_err, 180)}
            }.dump());
            return;
        }
    } else {
        std::filesystem::create_directories(abs_path.parent_path(), ec);
        if (ec) {
            reply_json(res, 500, json{
                {"ok", false},
                {"error", "server_error"},
                {"message", "failed to create destination directory"},
                {"detail", ec.message()}
            }.dump());
            return;
        }
    }

    auto rr = pqnas::restore_version_blob_to_path(vix, "user", fp_hex, rel_norm, version_id, abs_path);
    if (!rr.ok) {
        reply_json(res,
                   rr.error == "not_found" ? 404 : 500,
                   json{
                       {"ok", false},
                       {"error", rr.error.empty() ? "server_error" : rr.error},
                       {"message", rr.message.empty() ? "restore failed" : rr.message},
                       {"detail", pqnas::shorten(rr.detail, 180)}
                   }.dump());
        return;
    }
    // Refresh cached live file facts after restore so gallery list + thumb URLs
    // reflect the restored version immediately.
    {
        const std::uint64_t restored_size =
            rr.bytes > 0 ? static_cast<std::uint64_t>(rr.bytes)
                         : pqnas::file_size_u64_safe(abs_path);

        const std::int64_t restored_mtime =
            rr.mtime_epoch > 0
                ? static_cast<std::int64_t>(rr.mtime_epoch)
                : static_cast<std::int64_t>(file_mtime_epoch_safe(abs_path));

        const std::int64_t now_ts = static_cast<std::int64_t>(std::time(nullptr));

        if (auto* gidx = pqnas::get_gallery_meta_index()) {
            std::string gerr;
            (void)gidx->touch_file_facts(
                "user",
                fp_hex,
                rel_norm,
                restored_size,
                restored_mtime,
                now_ts,
                &gerr
            );
        }

        // Also refresh file_locations if you have a single-path fact update helper.
        // Use the exact helper from file_location_index.h/.cpp that updates
        // size_bytes + mtime_epoch for one logical path.
        //
        // Example shape only:
        //
        // if (auto* flix = pqnas::get_file_location_index()) {
        //     std::string ferr;
        //     if (!flix->YOUR_SINGLE_PATH_FACT_UPDATE_METHOD(
        //             fp_hex, rel_norm, restored_size, restored_mtime, &ferr)) {
        //         audit_warn("file_location_restore_refresh_failed", ferr, rel_norm);
        //     }
        // }
    }
    reply_json(res, 200, json{
        {"ok", true},
        {"scope_type", "user"},
        {"scope_id", fp_hex},
        {"path", rel_norm},
        {"restored_version_id", version_id},
        {"bytes", rr.bytes},
        {"mtime_epoch", rr.mtime_epoch},
        {"sha256_hex", rr.sha256_hex}
    }.dump());
});
//
// ---- Snapshots API (admin-only, v1) ----
//

// POST /api/v4/snapshots/create
// Body: { "volume":"data", "id":"OPTIONAL_ID" }
// If id is empty, server generates: MANUAL_<utc stamp>
srv.Post("/api/v4/snapshots/create", [&](const httplib::Request& req, httplib::Response& res) {
    std::string actor_fp;
    if (!require_admin_cookie_users_actor(req, res, COOKIE_KEY, users_path, &users, &actor_fp)) return;

    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto audit_fail = [&](const std::string& reason, int http, const std::string& detail="") {
        pqnas::AuditEvent ev;
        ev.event = "snapshots.create";
        ev.outcome = "fail";
        ev.f["actor_fp"] = actor_fp;
        ev.f["reason"] = reason;
        ev.f["http"] = std::to_string(http);
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    auto audit_ok = [&](const std::string& vol, const std::string& id, const std::string& path) {
        pqnas::AuditEvent ev;
        ev.event = "snapshots.create";
        ev.outcome = "ok";
        ev.f["actor_fp"] = actor_fp;
        ev.f["volume"] = vol;
        ev.f["id"] = id;
        ev.f["path"] = pqnas::shorten(path, 140);
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    // ---- tiny helpers ----
    auto trim = [](std::string s) {
        while (!s.empty() && (s.back()==' '||s.back()=='\n'||s.back()=='\r'||s.back()=='\t')) s.pop_back();
        size_t i=0; while (i<s.size() && (s[i]==' '||s[i]=='\n'||s[i]=='\r'||s[i]=='\t')) i++;
        return s.substr(i);
    };

    auto utc_stamp_for_id = [&]() -> std::string {
        // 2026-02-14T11-21-40.805Z (matches your existing style)
        using namespace std::chrono;
        auto now = system_clock::now();
        auto ms = duration_cast<milliseconds>(now.time_since_epoch()) % 1000;
        std::time_t tt = system_clock::to_time_t(now);
        std::tm tm{};
        gmtime_r(&tt, &tm);
        char buf[64];
        std::snprintf(buf, sizeof(buf),
            "%04d-%02d-%02dT%02d-%02d-%02d.%03dZ",
            tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday,
            tm.tm_hour, tm.tm_min, tm.tm_sec,
            (int)ms.count());
        return std::string(buf);
    };

    // ---- parse body ----
    json body;
    try {
        body = json::parse(req.body.empty() ? "{}" : req.body);
    } catch (...) {
        audit_fail("bad_json", 400);
        reply_json(res, 400, json{{"ok",false},{"error","bad_request"},{"message","invalid json"}}.dump());
        return;
    }

    std::string vol = trim(body.value("volume", ""));
    std::string id  = trim(body.value("id", ""));

    if (vol.empty()) {
        audit_fail("missing_volume", 400);
        reply_json(res, 400, json{{"ok",false},{"error","bad_request"},{"message","missing volume"}}.dump());
        return;
    }

    std::string backend, err;
    std::vector<SnapVol> vols;
    if (!load_snapshot_volumes_from_admin_settings(admin_settings_path, &backend, &vols, &err)) {
        audit_fail("settings_load_failed", 500, err);
        reply_json(res, 500, json{{"ok",false},{"error","server_error"},{"message","failed to load snapshot settings"}}.dump());
        return;
    }

    auto it = std::find_if(vols.begin(), vols.end(), [&](const SnapVol& v){ return v.name == vol; });
    if (it == vols.end()) {
        audit_fail("unknown_volume", 404, vol);
        reply_json(res, 404, json{{"ok",false},{"error","not_found"},{"message","unknown volume"}}.dump());
        return;
    }

    if (!it->enabled) {
        audit_fail("snapshots_disabled", 409, vol);
        reply_json(res, 409, json{
            {"ok", false},
            {"error", "disabled"},
            {"message", "snapshots are disabled for this volume"}
        }.dump());
        return;
    }

    const std::string source_subvolume = it->source_subvolume;
    const std::string snap_root        = it->snap_root;

    // Safety allowlist (same spirit as restore job script)
    auto starts_with = [](const std::string& s, const std::string& p){
        return s.size() >= p.size() && s.compare(0, p.size(), p) == 0;
    };
    if (!starts_with(source_subvolume, "/srv/pqnas/")) {
        audit_fail("live_path_not_allowed", 400, source_subvolume);
        reply_json(res, 400, json{{"ok",false},{"error","bad_request"},{"message","live_path not allowed"}}.dump());
        return;
    }
    if (!starts_with(snap_root, "/srv/pqnas/.snapshots/")) {
        audit_fail("snap_root_not_allowed", 400, snap_root);
        reply_json(res, 400, json{{"ok",false},{"error","bad_request"},{"message","snap_root not allowed"}}.dump());
        return;
    }

    if (id.empty()) {
        id = "MANUAL_" + utc_stamp_for_id();
    }

    // conservative id validation to prevent traversal and weird chars
    for (char c : id) {
        const bool ok =
            (c>='a'&&c<='z') || (c>='A'&&c<='Z') || (c>='0'&&c<='9') ||
            c=='_' || c=='-' || c=='.' || c=='T' || c=='Z';
        if (!ok) {
            audit_fail("invalid_id", 400, id);
            reply_json(res, 400, json{{"ok",false},{"error","bad_request"},{"message","invalid id (allowed: A-Z a-z 0-9 _ - . T Z)"}}.dump());
            return;
        }
    }

    std::error_code ec;
    std::filesystem::create_directories(snap_root, ec);

    const std::filesystem::path dst = std::filesystem::path(snap_root) / id;
    if (std::filesystem::exists(dst, ec) && !ec) {
        audit_fail("already_exists", 409, dst.string());
        reply_json(res, 409, json{{"ok",false},{"error","already_exists"},{"message","snapshot id already exists"}}.dump());
        return;
    }

    // Create snapshot (read-only)
    // Use sudo -n so it works when pqnas.service runs as user pqnas (recommended)
    // Execute: sudo -n btrfs subvolume snapshot -r <src> <dst>
    // without using shell

    auto run_btrfs_snapshot = [&](const std::string& src,
                                  const std::string& dst,
                                  std::string* output) -> int
    {
        if (output) output->clear();

        int pipefd[2];
        if (pipe(pipefd) != 0) return 127;

        pid_t pid = fork();
        if (pid < 0) {
            close(pipefd[0]);
            close(pipefd[1]);
            return 127;
        }

        if (pid == 0) {
            // child

            dup2(pipefd[1], STDOUT_FILENO);
            dup2(pipefd[1], STDERR_FILENO);

            close(pipefd[0]);
            close(pipefd[1]);

            execl("/usr/bin/sudo",
                  "sudo",
                  "-n",
                  "/usr/bin/btrfs",
                  "subvolume",
                  "snapshot",
                  "-r",
                  src.c_str(),
                  dst.c_str(),
                  (char*)nullptr);

            _exit(127);
        }

        // parent
        close(pipefd[1]);

        char buf[4096];
        ssize_t n;
        while ((n = read(pipefd[0], buf, sizeof(buf))) > 0) {
            if (output) output->append(buf, n);
        }

        close(pipefd[0]);

        int status = 0;
        waitpid(pid, &status, 0);

        if (WIFEXITED(status))
            return WEXITSTATUS(status);

        return 128;
    };

    // run snapshot
    std::string out;
    int rc = run_btrfs_snapshot(source_subvolume, dst.string(), &out);

    if (rc != 0) {

        // Common: sudo policy missing -> tell user clearly
        const std::string dlow = lower_ascii(out);
        if (dlow.find("a password is required") != std::string::npos ||
            dlow.find("not in the sudoers") != std::string::npos ||
            dlow.find("no tty present") != std::string::npos) {
            audit_fail("no_privs", 403, out);
            reply_json(res, 403, json{
                {"ok",false},
                {"error","no_privs"},
                {"message","sudo not permitted for btrfs snapshot; add sudoers rule for snapshot create"},
                {"detail", pqnas::shorten(out, 200)}
            }.dump());
            return;
        }

        audit_fail("snapshot_create_failed", 500, out);
        reply_json(res, 500, json{
            {"ok",false},
            {"error","server_error"},
            {"message","snapshot create failed"},
            {"detail", pqnas::shorten(out, 200)}
        }.dump());
        return;
    }

    // Probe new snapshot as sanity (same probe approach you use in list)
    std::string probe_detail;
    bool is_sub = is_btrfs_subvolume_sudo_n(dst.string(), &probe_detail);

    audit_ok(vol, id, dst.string());
    reply_json(res, 200, json{
        {"ok", true},
        {"volume", vol},
        {"id", id},
        {"path", dst.string()},
        {"is_btrfs_subvolume", is_sub},
        {"probe_detail", pqnas::shorten(probe_detail, 180)}
    }.dump());
});

// GET /api/v4/snapshots/volumes
srv.Get("/api/v4/snapshots/volumes", [&](const httplib::Request& req, httplib::Response& res) {
    std::string actor_fp;
    if (!require_admin_cookie_users_actor(req, res, COOKIE_KEY, users_path, &users, &actor_fp)) return;

    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto audit_emit = [&](const std::string& outcome, const std::string& reason, int http, const std::string& detail="") {
        pqnas::AuditEvent ev;
        ev.event = "snapshots.volumes";
        ev.outcome = outcome;
        ev.f["actor_fp"] = actor_fp;
        ev.f["http"] = std::to_string(http);
        if (!reason.empty()) ev.f["reason"] = reason;
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;
        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;
        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);
        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    std::string backend, err;
    std::vector<SnapVol> vols;
    if (!load_snapshot_volumes_from_admin_settings(admin_settings_path, &backend, &vols, &err)) {
        audit_emit("fail", "settings_load_failed", 500, err);
        reply_json(res, 500, json{{"ok",false},{"error","server_error"},{"message","failed to load snapshot settings"}}.dump());
        return;
    }

    json out_vols = json::array();
    for (const auto& v : vols) {
        out_vols.push_back(json{
            {"name", v.name},
            {"source_subvolume", v.source_subvolume},
            {"snap_root", v.snap_root},
            {"enabled", v.enabled}
        });
    }
	// Runtime user (for sudoers help text in snapshotmgr)
	std::string runtime_user;
	{
    	struct passwd* pw = getpwuid(geteuid());
    	if (pw && pw->pw_name) runtime_user = pw->pw_name;
	}
    audit_emit("ok", "", 200);
	reply_json(res, 200, json{
    	{"ok", true},
    	{"backend", backend},
	    {"volumes", out_vols},
    	{"runtime_user", runtime_user}
	}.dump());
	});


// GET /api/v4/snapshots/list?volume=data
srv.Get("/api/v4/snapshots/list", [&](const httplib::Request& req, httplib::Response& res) {
    std::string actor_fp;
    if (!require_admin_cookie_users_actor(req, res, COOKIE_KEY, users_path, &users, &actor_fp)) return;

    auto audit_ua = [&]() -> std::string {
        auto it = req.headers.find("User-Agent");
        return pqnas::shorten(it == req.headers.end() ? "" : it->second);
    };

    auto audit_fail = [&](const std::string& reason, int http, const std::string& detail="") {
        pqnas::AuditEvent ev;
        ev.event = "snapshots.list";
        ev.outcome = "fail";
        ev.f["actor_fp"] = actor_fp;
        ev.f["reason"] = reason;
        ev.f["http"] = std::to_string(http);
        if (!detail.empty()) ev.f["detail"] = pqnas::shorten(detail, 180);
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    auto audit_ok = [&](const std::string& vol, size_t n) {
        pqnas::AuditEvent ev;
        ev.event = "snapshots.list";
        ev.outcome = "ok";
        ev.f["actor_fp"] = actor_fp;
        ev.f["volume"] = vol;
        ev.f["count"] = std::to_string((unsigned long long)n);
        ev.f["ip"] = req.remote_addr.empty() ? "?" : req.remote_addr;

        auto it_cf = req.headers.find("CF-Connecting-IP");
        if (it_cf != req.headers.end()) ev.f["cf_ip"] = it_cf->second;

        auto it_xff = req.headers.find("X-Forwarded-For");
        if (it_xff != req.headers.end()) ev.f["xff"] = pqnas::shorten(it_xff->second, 120);

        ev.f["ua"] = audit_ua();
        audit_append(ev);
    };

    std::string vol = req.has_param("volume") ? req.get_param_value("volume") : "";
    if (vol.empty()) {
        audit_fail("missing_volume", 400);
        reply_json(res, 400, json{{"ok",false},{"error","bad_request"},{"message","missing volume"}}.dump());
        return;
    }

    std::string backend, err;
    std::vector<SnapVol> vols;
    if (!load_snapshot_volumes_from_admin_settings(admin_settings_path, &backend, &vols, &err)) {
        audit_fail("settings_load_failed", 500, err);
        reply_json(res, 500, json{{"ok",false},{"error","server_error"},{"message","failed to load snapshot settings"}}.dump());
        return;
    }

    auto it = std::find_if(vols.begin(), vols.end(), [&](const SnapVol& v){ return v.name == vol; });
    if (it == vols.end()) {
        audit_fail("unknown_volume", 404, vol);
        reply_json(res, 404, json{{"ok",false},{"error","not_found"},{"message","unknown volume"}}.dump());
        return;
    }

    const std::string snap_root = it->snap_root;
    std::error_code ec;
    if (!std::filesystem::exists(snap_root, ec) || ec) {
        audit_fail("snap_root_missing", 404, snap_root);
        reply_json(res, 404, json{{"ok",false},{"error","not_found"},{"message","snap_root not found"}}.dump());
        return;
    }

struct Item {
    std::string id;
    std::string path;
    std::uint64_t mtime_unix{0};
    bool is_subvol{false};
    std::string probe;      // "ok" | "no_privs" | "err"
    std::string probe_detail;
};

std::vector<Item> items;

for (auto& de : std::filesystem::directory_iterator(snap_root, ec)) {
    if (ec) break;
    if (!de.is_directory(ec)) continue;

    const auto p = de.path();
    const std::string id  = p.filename().string();
    const std::string abs = p.string();

    // mtime
    std::uint64_t mt = 0;
    std::error_code ec2;
    auto ftime = std::filesystem::last_write_time(p, ec2);
    if (!ec2) {
        auto sctp = std::chrono::time_point_cast<std::chrono::seconds>(ftime);
        mt = (std::uint64_t)sctp.time_since_epoch().count();
    }

    // Probe btrfs subvol via sudo -n; if sudo not allowed, we still list it but flag probe.
    std::string detail;
    bool is_sub = false;
    std::string probe = "ok";

    {
        // popen_capture returns the stderr text; check for common sudo failure hints
        is_sub = is_btrfs_subvolume_sudo_n(abs, &detail);

        // If it isn't a subvol, it could be junk OR probe failed due to sudo policy.
        // Heuristic: "sudo:" / "a password is required" => no_privs
        const std::string dlow = lower_ascii(detail);
        if (!is_sub) {
            if (dlow.find("sudo:") != std::string::npos ||
                dlow.find("a password is required") != std::string::npos ||
                dlow.find("no tty present") != std::string::npos ||
                dlow.find("not in the sudoers file") != std::string::npos) {
                probe = "no_privs";
            } else if (!detail.empty() && dlow.find("operation not permitted") != std::string::npos) {
                // can also happen if sudo isn't used / allowed
                probe = "no_privs";
            } else {
                probe = "ok"; // real "not a subvolume" (junk dir)
            }
        }
    }

    items.push_back(Item{id, abs, mt, is_sub, probe, detail});
}


    std::sort(items.begin(), items.end(), [&](const Item& a, const Item& b){
        // newest first
        if (a.mtime_unix != b.mtime_unix) return a.mtime_unix > b.mtime_unix;
        return a.id > b.id;
    });

	json snaps = json::array();
	for (const auto& s : items) {
    	snaps.push_back(json{
       		{"id", s.id},
	        {"path", s.path},
	        {"created_utc", ""},                 // keep blank if you want
       		{"readonly", false},
	        {"is_btrfs_subvolume", s.is_subvol}, // <-- ✅ COMMA was missing after this before
       		{"probe", s.probe},                  // "ok" | "no_privs" | ...
       		{"probe_detail", pqnas::shorten(s.probe_detail, 180)}
	    });
	}


    audit_ok(vol, snaps.size());
    reply_json(res, 200, json{
        {"ok", true},
        {"volume", vol},
        {"snap_root", snap_root},
        {"snapshots", snaps}
    }.dump());
});


